            background: white !important; 
            margin: 0 !important; 
            padding: 0 !important;
            width: 100% !important;
            height: 100% !important;
          }

          .print-wrap { 
            padding: 0 !important; 
            margin: 0 !important;
            background: white !important; 
            max-width: none !important;
            width: 100% !important;
            min-height: auto !important;
          }
          
          .print-card { 
            border-radius: 0 !important; 
