// Not all forms need it — only logo and (future) team_contacts.
export const BlockConfigContext = createContext({ productionId: null, onAfterPersist: null })

// ─── Generic styled inputs ───────────────────────────────────
const inputStyle = {
  width: '100%',
  padding: '6px 8px',
  fontSize: '12px',
  border: '1px solid #cbd5e1',
  borderRadius: 4,
  background: '#ffffff',
