// ─── Form: addresses_block ───────────────────────────────────
function AddressesForm({ config, onChange }) {
  const [lines, setLines] = useState(
    Array.isArray(config?.lines) ? config.lines : []
  )

  useDebouncedSave({ lines }, (v) => onChange(v))

  const addLine = () => setLines(L => [...L, { label: '', address: '' }])
  const removeLine = (idx) => setLines(L => L.filter((_, i) => i !== idx))
  const updateLine = (idx, field, value) => {
    setLines(L => L.map((l, i) => i === idx ? { ...l, [field]: value } : l))
  }
  const moveLine = (idx, dir) => {
    const newIdx = idx + dir
    if (newIdx < 0 || newIdx >= lines.length) return
    setLines(L => {
      const out = [...L]
      const [item] = out.splice(idx, 1)
      out.splice(newIdx, 0, item)
      return out
    })
  }

  return (
    <>
      <div style={fieldGroupStyle}>
        <label style={labelStyle}>Address lines</label>
        {lines.length === 0 && (
          <div style={{ ...helpStyle, padding: 8, textAlign: 'center', border: '1px dashed #e2e8f0', borderRadius: 4 }}>
            No address lines yet.
          </div>
        )}
        {lines.map((line, idx) => (
          <div key={idx} style={{
            display: 'grid',
            gridTemplateColumns: '90px 1fr auto',
            gap: 4,
            marginBottom: 4,
            alignItems: 'center',
          }}>
            <input
              type="text"
              value={line.label || ''}
              onChange={e => updateLine(idx, 'label', e.target.value)}
              placeholder="Label"
              style={{ ...inputStyle, fontSize: 11 }}
            />
            <input
              type="text"
              value={line.address || ''}
              onChange={e => updateLine(idx, 'address', e.target.value)}
              placeholder="Address"
              style={{ ...inputStyle, fontSize: 11 }}
            />
            <div style={{ display: 'flex', gap: 2 }}>
              <button
                type="button"
                onClick={() => moveLine(idx, -1)}
                disabled={idx === 0}
                title="Move up"
                style={{
                  padding: '2px 5px', fontSize: 11,
                  background: 'transparent', border: '1px solid #e2e8f0',
                  borderRadius: 3, cursor: idx === 0 ? 'default' : 'pointer',
                  color: idx === 0 ? '#cbd5e1' : '#64748b',
                }}
              >↑</button>
              <button
                type="button"
                onClick={() => moveLine(idx, 1)}
                disabled={idx === lines.length - 1}
                title="Move down"
                style={{
                  padding: '2px 5px', fontSize: 11,
                  background: 'transparent', border: '1px solid #e2e8f0',
                  borderRadius: 3, cursor: idx === lines.length - 1 ? 'default' : 'pointer',
                  color: idx === lines.length - 1 ? '#cbd5e1' : '#64748b',
                }}
              >↓</button>
              <button
                type="button"
                onClick={() => removeLine(idx)}
                title="Remove line"
                style={{
                  padding: '2px 5px', fontSize: 11,
                  background: 'transparent', border: '1px solid #fecaca',
                  borderRadius: 3, cursor: 'pointer',
                  color: '#dc2626',
                }}
              >✕</button>
            </div>
          </div>
        ))}
        <button
          type="button"
          onClick={addLine}
          style={{
            width: '100%', padding: '5px 8px', fontSize: 11,
            background: '#ffffff', border: '1px dashed #cbd5e1',
            borderRadius: 4, cursor: 'pointer', color: '#475569',
            marginTop: 4,
          }}
        >+ Add address line</button>
      </div>
    </>
  )
}

// ─── Form: logo_image ────────────────────────────────────────
function LogoImageForm({ config, onChange }) {
  const { productionId, onAfterPersist } = useContext(BlockConfigContext)

  const [maxHeight, setMaxHeight] = useState(
    typeof config?.maxHeight === 'number' ? config.maxHeight : 60
  )
  const [align, setAlign] = useState(config?.align || 'center')
  useDebouncedSave({ maxHeight, align }, (v) => onChange(v))

  // Logo state
  const [previewUrl, setPreviewUrl] = useState(null)
  const [loadingPreview, setLoadingPreview] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [uploadError, setUploadError] = useState(null)
  const [isDragging, setIsDragging] = useState(false)
  const fileInputRef = useRef(null)

  // Load current logo signed URL
  useEffect(() => {
    let cancelled = false
    async function load() {
      if (!productionId) { setLoadingPreview(false); return }
      setLoadingPreview(true)
      try {
        const url = await getProductionLogoUrl(productionId)
        if (!cancelled) setPreviewUrl(url)
      } catch (e) {
        console.error('[LogoImageForm] load preview error', e)
      } finally {
        if (!cancelled) setLoadingPreview(false)
      }
    }
    load()
    return () => { cancelled = true }
  }, [productionId])

  async function handleFile(file) {
    if (!file || !productionId) return
    setUploadError(null)

    // Validate type
    const validTypes = ['image/png', 'image/jpeg', 'image/webp', 'image/svg+xml']
    if (!validTypes.includes(file.type)) {
      setUploadError('Unsupported format. Use PNG, JPEG, WebP or SVG.')
      return
    }
    // Validate size (5MB pre-resize)
    if (file.size > 5 * 1024 * 1024) {
      setUploadError('File too large (max 5MB).')
      return
    }

    setUploading(true)
    try {
      const resized = await resizeImage(file, { maxWidth: 600, maxHeight: 600 })
      const ext = fileExtension(file)
      await uploadProductionLogo(productionId, resized, ext)
      // Refresh preview
      const url = await getProductionLogoUrl(productionId)
      setPreviewUrl(url)
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[LogoImageForm] upload error', e)
      setUploadError(e.message || 'Upload failed')
    } finally {
      setUploading(false)
    }
  }

  async function handleRemove() {
    if (!productionId) return
    if (!confirm('Remove the current logo?')) return
    setUploading(true)
    setUploadError(null)
    try {
      await deleteProductionLogo(productionId)
      setPreviewUrl(null)
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[LogoImageForm] delete error', e)
      setUploadError(e.message || 'Delete failed')
    } finally {
      setUploading(false)
    }
  }

  const onDragOver = (e) => { e.preventDefault(); setIsDragging(true) }
  const onDragLeave = () => setIsDragging(false)
  const onDrop = (e) => {
    e.preventDefault()
    setIsDragging(false)
    const file = e.dataTransfer.files?.[0]
    if (file) handleFile(file)
  }

  return (
    <>
      {/* Upload section */}
      <div style={fieldGroupStyle}>
        <label style={labelStyle}>Logo file</label>

        {loadingPreview ? (
          <div style={{ padding: 12, textAlign: 'center', fontSize: 11, color: '#94a3b8' }}>
            Loading…
          </div>
        ) : previewUrl ? (
          <div style={{
            border: '1px solid #e2e8f0',
            borderRadius: 6,
            padding: 10,
            background: '#fafafa',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 8,
          }}>
            <img
              src={previewUrl}
              alt="logo preview"
              style={{ maxWidth: '100%', maxHeight: 80, objectFit: 'contain' }}
            />
            <div style={{ display: 'flex', gap: 6 }}>
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                style={{
                  padding: '4px 10px', fontSize: 11,
                  background: '#ffffff', border: '1px solid #cbd5e1',
                  borderRadius: 4, cursor: 'pointer', color: '#475569',
                }}
              >
                Replace
              </button>
              <button
                type="button"
                onClick={handleRemove}
                disabled={uploading}
                style={{
                  padding: '4px 10px', fontSize: 11,
                  background: '#ffffff', border: '1px solid #fecaca',
                  borderRadius: 4, cursor: 'pointer', color: '#dc2626',
                }}
              >
                Remove
              </button>
            </div>
          </div>
        ) : (
          <div
            onClick={() => fileInputRef.current?.click()}
            onDragOver={onDragOver}
            onDragLeave={onDragLeave}
            onDrop={onDrop}
            style={{
              border: '2px dashed ' + (isDragging ? '#2563eb' : '#cbd5e1'),
              borderRadius: 6,
              padding: '20px 12px',
              textAlign: 'center',
              background: isDragging ? '#eff6ff' : '#fafafa',
              cursor: 'pointer',
              transition: 'all 0.15s',
            }}
          >
            <div style={{ fontSize: 24, marginBottom: 4 }}>📁</div>
            <div style={{ fontSize: 12, fontWeight: 500, color: '#475569', marginBottom: 2 }}>
              {uploading ? 'Uploading…' : 'Click or drop a logo file'}
            </div>
            <div style={{ fontSize: 10, color: '#94a3b8' }}>
              PNG, JPEG, WebP or SVG. Max 5MB.
            </div>
          </div>
        )}

        <input
          ref={fileInputRef}
          type="file"
          accept="image/png,image/jpeg,image/webp,image/svg+xml"
          onChange={(e) => {
            const file = e.target.files?.[0]
            if (file) handleFile(file)
            e.target.value = '' // reset so same-file re-upload works
          }}
          style={{ display: 'none' }}
        />

        {uploadError && (
          <div style={{
            marginTop: 6, padding: '6px 8px',
            background: '#fef2f2', color: '#991b1b',
            border: '1px solid #fecaca', borderRadius: 4,
            fontSize: 10,
          }}>
            ⚠ {uploadError}
          </div>
        )}
      </div>

      <div style={fieldGroupStyle}>
        <label style={labelStyle}>Max height (px)</label>
        <input
          type="number"
          min={20}
          max={200}
          value={maxHeight}
          onChange={e => setMaxHeight(Number(e.target.value) || 60)}
          style={inputStyle}
        />
        <div style={helpStyle}>
          The logo will scale to fit this height while keeping its proportions.
        </div>
      </div>
      <div style={fieldGroupStyle}>
        <label style={labelStyle}>Alignment</label>
        <select value={align} onChange={e => setAlign(e.target.value)} style={inputStyle}>
          <option value="left">Left</option>
          <option value="center">Center</option>
          <option value="right">Right</option>
        </select>
      </div>
    </>
  )
}

// ─── Form: team_contacts ─────────────────────────────────────
function TeamContactsForm({ config, onChange }) {
  const { productionId, onAfterPersist } = useContext(BlockConfigContext)

  // Block-level config (still debounced-saved)
  const [layout, setLayout] = useState(config?.layout || 'inline')
  const [showEmail, setShowEmail] = useState(config?.showEmail !== false)
  const [syncWithCrew, setSyncWithCrew] = useState(config?.autoFromDB !== false)
  useDebouncedSave({ layout, showEmail, autoFromDB: syncWithCrew }, (v) => onChange({ ...config, ...v }))

  // Contacts list state
  const [contacts, setContacts] = useState([])
  const [loadingList, setLoadingList] = useState(true)
  const [busyAction, setBusyAction] = useState(false)
  const [listError, setListError] = useState(null)

  // Autocomplete state
  const [searchQuery, setSearchQuery] = useState('')
  const [searchResults, setSearchResults] = useState([])
  const [searching, setSearching] = useState(false)
  const [showDropdown, setShowDropdown] = useState(false)
  const searchTimerRef = useRef(null)

  const reloadList = async () => {
    if (!productionId) { setLoadingList(false); return }
    setLoadingList(true)
    setListError(null)
    try {
      const list = await loadResolvedTeamContacts(productionId, syncWithCrew)
      setContacts(list)
    } catch (e) {
      console.error('[TeamContactsForm] reload error', e)
      setListError(e.message || String(e))
    } finally {
      setLoadingList(false)
    }
  }

  useEffect(() => { reloadList() }, [productionId, syncWithCrew])

  // Debounced search
  useEffect(() => {
    if (searchTimerRef.current) clearTimeout(searchTimerRef.current)
    if (!searchQuery.trim()) {
      setSearchResults([])
      setSearching(false)
      return
    }
    setSearching(true)
    searchTimerRef.current = setTimeout(async () => {
      try {
        const excludeIds = contacts.filter(c => c.crew_id).map(c => c.crew_id)
        const results = await searchCrewForContacts(productionId, searchQuery, excludeIds)
        setSearchResults(results)
      } catch (e) {
        console.error('[TeamContactsForm] search error', e)
      } finally {
        setSearching(false)
      }
    }, 250)
    return () => { if (searchTimerRef.current) clearTimeout(searchTimerRef.current) }
  }, [searchQuery, contacts, productionId])

  const handlePickCrew = async (crew) => {
    setBusyAction(true)
    setListError(null)
    try {
      const order = 100 + contacts.length * 10
      await addCrewContact(productionId, crew, {
        snapshotData: !syncWithCrew, // freeze data if sync is off
        display_order: order,
      })
      setSearchQuery('')
      setSearchResults([])
      setShowDropdown(false)
      await reloadList()
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[TeamContactsForm] pick crew error', e)
      setListError(e.message || String(e))
    } finally {
      setBusyAction(false)
    }
  }

  const handleAddManual = async () => {
    setBusyAction(true)
    setListError(null)
    try {
      const order = 500 + contacts.length * 10
      await addManualContact(productionId, {
        name: searchQuery.trim() || '',
        display_order: order,
      })
      setSearchQuery('')
      setSearchResults([])
      setShowDropdown(false)
      await reloadList()
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[TeamContactsForm] add manual error', e)
      setListError(e.message || String(e))
    } finally {
      setBusyAction(false)
    }
  }

  const handleFieldEdit = async (contact, field, value) => {
    if (!contact.override_id) return
    setBusyAction(true)
    setListError(null)
    try {
      const overrideField = field + '_override'
      await updateContactOverride(contact.override_id, { [overrideField]: value })
      await reloadList()
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[TeamContactsForm] edit error', e)
      setListError(e.message || String(e))
    } finally {
      setBusyAction(false)
    }
  }

  const handleToggleHide = async (contact) => {
    if (!contact.override_id) return
    setBusyAction(true)
    setListError(null)
    try {
      await updateContactOverride(contact.override_id, { hidden: !contact.hidden })
      await reloadList()
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[TeamContactsForm] toggle hide error', e)
      setListError(e.message || String(e))
    } finally {
      setBusyAction(false)
    }
  }

  const handleDelete = async (contact) => {
    if (!contact.override_id) return
    const msg = contact.crew_id
      ? 'Remove this contact from the Transport List?'
      : 'Remove this manual contact?'
    if (!confirm(msg)) return
    setBusyAction(true)
    setListError(null)
    try {
      await deleteContactOverride(contact.override_id)
      await reloadList()
      if (onAfterPersist) onAfterPersist()
    } catch (e) {
      console.error('[TeamContactsForm] delete error', e)
      setListError(e.message || String(e))
    } finally {
      setBusyAction(false)
    }
  }

  return (
    <>
      <div style={fieldGroupStyle}>
        <label style={labelStyle}>Layout</label>
        <select value={layout} onChange={e => setLayout(e.target.value)} style={inputStyle}>
          <option value="inline">Inline (one line, separator dots)</option>
          <option value="rows">Rows (one contact per line)</option>
        </select>
      </div>
      <div style={fieldGroupStyle}>
        <label style={{ ...labelStyle, display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer' }}>
          <input type="checkbox" checked={showEmail} onChange={e => setShowEmail(e.target.checked)} style={{ margin: 0 }} />
          Show email addresses
        </label>
      </div>
      <div style={fieldGroupStyle}>
        <label style={{ ...labelStyle, display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer' }}>
          <input type="checkbox" checked={syncWithCrew} onChange={e => setSyncWithCrew(e.target.checked)} style={{ margin: 0 }} />
          Sync with crew updates
        </label>
        <div style={helpStyle}>
          When ON: contact data (name, phone, etc.) is read live from the crew database.
          When OFF: data is frozen as it was when you added the contact.
        </div>
      </div>

      {/* Search + Add */}
      <div style={{ ...fieldGroupStyle, marginTop: 14, borderTop: '1px dashed #e2e8f0', paddingTop: 12, position: 'relative' }}>
        <label style={labelStyle}>Add contact</label>
        <input
          type="text"
          value={searchQuery}
          onChange={e => { setSearchQuery(e.target.value); setShowDropdown(true) }}
          onFocus={() => setShowDropdown(true)}
          placeholder="Search crew by name…"
          style={inputStyle}
          disabled={busyAction}
        />

        {showDropdown && searchQuery.trim() && (
          <div style={{
            position: 'absolute', top: '100%', left: 0, right: 0,
            marginTop: 2, zIndex: 20,
            background: '#ffffff',
            border: '1px solid #cbd5e1', borderRadius: 6,
            boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
            maxHeight: 240, overflowY: 'auto',
          }}>
            {searching ? (
              <div style={{ padding: 10, fontSize: 11, color: '#94a3b8', textAlign: 'center' }}>
                Searching…
              </div>
            ) : (
              <>
                {searchResults.map(crew => (
                  <button
                    key={crew.id}
                    type="button"
                    onClick={() => handlePickCrew(crew)}
                    style={{
                      display: 'block', width: '100%', textAlign: 'left',
                      padding: '7px 10px',
                      background: 'transparent', border: 'none',
                      cursor: 'pointer', borderBottom: '1px solid #f1f5f9',
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = '#f8fafc'}
                    onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                  >
                    <div style={{ fontSize: 12, fontWeight: 600, color: '#0f172a' }}>
                      {crew.full_name}
                    </div>
                    <div style={{ fontSize: 10, color: '#64748b', marginTop: 1 }}>
                      {[crew.role, crew.department].filter(Boolean).join(' · ') || 'no role/dept'}
                      {crew.phone && <span> · {crew.phone}</span>}
                    </div>
                  </button>
                ))}
                <button
                  type="button"
                  onClick={handleAddManual}
                  style={{
                    display: 'block', width: '100%', textAlign: 'left',
                    padding: '8px 10px',
                    background: '#fffbeb',
                    border: 'none', cursor: 'pointer',
                    fontSize: 11, fontWeight: 600, color: '#92400e',
                  }}
                  onMouseEnter={e => e.currentTarget.style.background = '#fef3c7'}
                  onMouseLeave={e => e.currentTarget.style.background = '#fffbeb'}
                >
                  + Add &ldquo;{searchQuery}&rdquo; as manual contact
                </button>
              </>
            )}
          </div>
        )}
        <div style={helpStyle}>
          Start typing a name to find crew members, or add a manual contact.
        </div>
      </div>

      {/* Contacts list */}
      <div style={{ ...fieldGroupStyle, marginTop: 8 }}>
        <label style={labelStyle}>
          Contacts ({contacts.filter(c => !c.hidden).length} visible · {contacts.length} total)
        </label>

        {listError && (
          <div style={{ padding: '6px 8px', marginBottom: 6, background: '#fef2f2', color: '#991b1b', border: '1px solid #fecaca', borderRadius: 4, fontSize: 10 }}>
            ⚠ {listError}
          </div>
        )}

        {loadingList ? (
          <div style={{ padding: 12, textAlign: 'center', fontSize: 11, color: '#94a3b8' }}>Loading…</div>
        ) : contacts.length === 0 ? (
          <div style={{ ...helpStyle, padding: 10, textAlign: 'center', border: '1px dashed #e2e8f0', borderRadius: 4 }}>
            No contacts yet. Use the search above to add crew members.
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6, opacity: busyAction ? 0.5 : 1, pointerEvents: busyAction ? 'none' : 'auto' }}>
            {contacts.map(c => (
              <div key={c.key} style={{
                border: '1px solid ' + (c.hidden ? '#fde68a' : '#e2e8f0'),
                background: c.hidden ? '#fffbeb' : '#ffffff',
                borderRadius: 6,
                padding: 8,
                opacity: c.hidden ? 0.65 : 1,
              }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4, marginBottom: 4 }}>
                  <input
                    type="text"
                    defaultValue={c.name}
                    onBlur={e => { if (e.target.value !== c.name) handleFieldEdit(c, 'name', e.target.value) }}
                    placeholder="Name"
                    style={{ ...inputStyle, fontSize: 11, fontWeight: 600 }}
                  />
                  <input
                    type="text"
                    defaultValue={c.role}
                    onBlur={e => { if (e.target.value !== c.role) handleFieldEdit(c, 'role', e.target.value) }}
                    placeholder="Role"
                    style={{ ...inputStyle, fontSize: 11 }}
                  />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4 }}>
                  <input
                    type="text"
                    defaultValue={c.phone}
                    onBlur={e => { if (e.target.value !== c.phone) handleFieldEdit(c, 'phone', e.target.value) }}
                    placeholder="Phone"
                    style={{ ...inputStyle, fontSize: 11 }}
                  />
                  <input
                    type="text"
                    defaultValue={c.email}
                    onBlur={e => { if (e.target.value !== c.email) handleFieldEdit(c, 'email', e.target.value) }}
                    placeholder="Email"
                    style={{ ...inputStyle, fontSize: 11 }}
                  />
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 6 }}>
                  <span style={{ fontSize: 9, color: '#94a3b8', fontStyle: 'italic' }}>
                    {c.crew_id ? `Crew: ${c.crew_id}` : 'Manual contact'}
                    {syncWithCrew && c.crew_id ? ' · live sync' : ''}
                  </span>
                  <div style={{ display: 'flex', gap: 4 }}>
                    <button
                      type="button"
                      onClick={() => handleToggleHide(c)}
                      title={c.hidden ? 'Show in TL' : 'Hide from TL'}
                      style={{
                        padding: '3px 8px', fontSize: 10,
                        background: 'transparent', border: '1px solid #cbd5e1',
                        borderRadius: 3, cursor: 'pointer',
                        color: c.hidden ? '#92400e' : '#64748b',
                      }}
                    >
                      {c.hidden ? '👁 Show' : '◌ Hide'}
                    </button>
                    <button
                      type="button"
                      onClick={() => handleDelete(c)}
                      title="Remove contact"
                      style={{
                        padding: '3px 8px', fontSize: 10,
                        background: 'transparent', border: '1px solid #fecaca',
                        borderRadius: 3, cursor: 'pointer', color: '#dc2626',
                      }}
                    >
                      ✕ Remove
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </>
  )
}

// ─── Form: emergency_contacts ────────────────────────────────
function EmergencyContactsForm({ config, onChange }) {
  const [contacts, setContacts] = useState(
    Array.isArray(config?.contacts) ? config.contacts : []
  )

  useDebouncedSave({ contacts }, (v) => onChange(v))

  const addContact = () => setContacts(C => [...C, { label: '', phone: '' }])
  const removeContact = (idx) => setContacts(C => C.filter((_, i) => i !== idx))
  const updateContact = (idx, field, value) => {
    setContacts(C => C.map((c, i) => i === idx ? { ...c, [field]: value } : c))
  }
  const moveContact = (idx, dir) => {
    const newIdx = idx + dir
    if (newIdx < 0 || newIdx >= contacts.length) return
    setContacts(C => {
      const out = [...C]
      const [item] = out.splice(idx, 1)
      out.splice(newIdx, 0, item)
      return out
    })
  }

  return (
    <div style={fieldGroupStyle}>
      <label style={labelStyle}>Emergency contacts</label>
      {contacts.length === 0 && (
        <div style={{ ...helpStyle, padding: 8, textAlign: 'center', border: '1px dashed #e2e8f0', borderRadius: 4 }}>
          No emergency contacts yet.
        </div>
      )}
      {contacts.map((c, idx) => (
        <div key={idx} style={{
          display: 'grid',
          gridTemplateColumns: '110px 1fr auto',
          gap: 4,
          marginBottom: 4,
          alignItems: 'center',
        }}>
          <input
            type="text"
            value={c.label || ''}
            onChange={e => updateContact(idx, 'label', e.target.value)}
            placeholder="Label (e.g. Police)"
            style={{ ...inputStyle, fontSize: 11 }}
          />
          <input
            type="text"
            value={c.phone || ''}
            onChange={e => updateContact(idx, 'phone', e.target.value)}
            placeholder="Phone"
            style={{ ...inputStyle, fontSize: 11 }}
          />
          <div style={{ display: 'flex', gap: 2 }}>
            <button
              type="button"
              onClick={() => moveContact(idx, -1)}
              disabled={idx === 0}
              title="Move up"
              style={{
                padding: '2px 5px', fontSize: 11,
                background: 'transparent', border: '1px solid #e2e8f0',
                borderRadius: 3, cursor: idx === 0 ? 'default' : 'pointer',
                color: idx === 0 ? '#cbd5e1' : '#64748b',
              }}
            >↑</button>
            <button
              type="button"
              onClick={() => moveContact(idx, 1)}
              disabled={idx === contacts.length - 1}
              title="Move down"
              style={{
                padding: '2px 5px', fontSize: 11,
                background: 'transparent', border: '1px solid #e2e8f0',
                borderRadius: 3, cursor: idx === contacts.length - 1 ? 'default' : 'pointer',
                color: idx === contacts.length - 1 ? '#cbd5e1' : '#64748b',
              }}
            >↓</button>
            <button
              type="button"
              onClick={() => removeContact(idx)}
              title="Remove"
              style={{
                padding: '2px 5px', fontSize: 11,
                background: 'transparent', border: '1px solid #fecaca',
                borderRadius: 3, cursor: 'pointer',
                color: '#dc2626',
              }}
            >✕</button>
          </div>
        </div>
      ))}
      <button
        type="button"
        onClick={addContact}
        style={{
          width: '100%', padding: '5px 8px', fontSize: 11,
          background: '#ffffff', border: '1px dashed #cbd5e1',
          borderRadius: 4, cursor: 'pointer', color: '#475569',
          marginTop: 4,
        }}
      >+ Add emergency contact</button>
    </div>
  )
}

// ─── Main exported component ─────────────────────────────────
/**
 * Renders the config form for a given block.
 * 
 * Props:
 *   block    — { id, block_type, config, width, ... }
 *   onPatch  — (patch: { config?, width? }) => Promise<void>
 *              called by individual forms when their state changes.
 *              The parent component is responsible for persisting to DB
 *              and reloading.
 */
export function BlockConfigForm({ block, onPatch, productionId }) {
  const handleConfigChange = (newConfig) => {
    onPatch({ config: newConfig })
  }
  const handleWidthChange = (newWidth) => {
    onPatch({ width: newWidth })
  }

  const renderForm = () => {
    switch (block.block_type) {
      case 'production_title':
        return <TitleForm config={block.config} onChange={handleConfigChange} />
      case 'date_today':
        return <DateTodayForm config={block.config} onChange={handleConfigChange} />
      case 'free_text_header':
        return (
          <FreeTextForm
            config={block.config}
            onChange={handleConfigChange}
            sizeOptions={[
              { value: 'xs', label: 'Extra small (9px)' },
              { value: 'sm', label: 'Small (11px)' },
              { value: 'md', label: 'Medium (13px)' },
              { value: 'lg', label: 'Large (15px)' },
            ]}
          />
        )
      case 'free_text_footer':
        return (
          <FreeTextForm
            config={block.config}
            onChange={handleConfigChange}
            sizeOptions={[
              { value: 'xs', label: 'Extra small (9px)' },
              { value: 'sm', label: 'Small (11px)' },
              { value: 'md', label: 'Medium (13px)' },
            ]}
          />
        )
      case 'page_number':
        return <PageNumberForm config={block.config} onChange={handleConfigChange} />
      case 'shooting_day_counter':
        return <ShootingDayForm config={block.config} onChange={handleConfigChange} />
      case 'addresses_block':
        return <AddressesForm config={block.config} onChange={(lines) => handleConfigChange({ ...block.config, lines: lines.lines })} />
      case 'logo_image':
        return <LogoImageForm config={block.config} onChange={handleConfigChange} productionId={productionId} />
      case 'team_contacts':
        return <TeamContactsForm config={block.config} onChange={handleConfigChange} />
      case 'emergency_contacts':
        return <EmergencyContactsForm config={block.config} onChange={(contacts) => handleConfigChange({ ...block.config, contacts: contacts.contacts })} />
      default:
        return (
          <div style={{ fontStyle: 'italic', color: '#94a3b8', textAlign: 'center', padding: 12, fontSize: 11 }}>
            Unknown block type: <code>{block.block_type}</code>
          </div>
        )
    }
  }

  return (
    <div>
      {renderForm()}
      <div style={{ borderTop: '1px dashed #e2e8f0', marginTop: 10, paddingTop: 10 }}>
        <WidthSelector value={block.width} onChange={handleWidthChange} />
      </div>
    </div>
  )
}

'use client'
import { useEffect, useState } from 'react'
import { supabase } from './supabase'
import { getProductionId } from './production'
import { COLUMNS_CATALOG, CAPTAIN_PRESET, getCatalogByCategory } from './listColumnsCatalog'
import { DndContext, PointerSensor, useSensor, useSensors, closestCenter } from '@dnd-kit/core'
import { arrayMove, SortableContext, verticalListSortingStrategy, useSortable } from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'

const SIDEBAR_W = 360

function SortableColumnRow({ column, isEditing, def, onStartEdit, onCancelEdit, onDelete }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: column.id })
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
    padding: '7px 10px',
    background: isEditing ? '#fffbeb' : '#f8fafc',
    border: '1px solid ' + (isEditing ? '#fbbf24' : '#e2e8f0'),
    borderRadius: '7px',
    touchAction: 'none',
  }
  return (
    <div ref={setNodeRef} style={style}>
      <span
        {...attributes}
        {...listeners}
        style={{ cursor: 'grab', color: '#94a3b8', fontSize: '14px', flexShrink: 0, userSelect: 'none', padding: '0 4px' }}
        title="Drag to reorder">
        ⋮⋮
      </span>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontSize: '12px', fontWeight: '700', color: '#0f172a', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {column.header_label}
        </div>
        <div style={{ fontSize: '10px', color: '#64748b', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {def ? def.label : <span style={{ color: '#dc2626' }}>?{column.source_field}</span>} · {column.width}
        </div>
      </div>
      <button
        type="button"
        onClick={() => isEditing ? onCancelEdit() : onStartEdit(column)}
        style={{ background: isEditing ? '#fbbf24' : 'white', border: '1px solid #e2e8f0', color: isEditing ? 'white' : '#64748b', borderRadius: '5px', padding: '3px 8px', cursor: 'pointer', fontSize: '11px', fontWeight: '700', flexShrink: 0 }}>
        {isEditing ? 'cancel' : 'edit'}
      </button>
      <button
        type="button"
        onClick={() => onDelete(column)}
        style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#dc2626', borderRadius: '5px', padding: '3px 8px', cursor: 'pointer', fontSize: '11px', fontWeight: '700', flexShrink: 0 }}>
        delete
      </button>
    </div>
  )
}

