  { value: '200px', label: '200px (very wide)' },
  { value: '1fr',   label: 'Flex (fill remaining space)' },
]

export function ColumnsEditorSidebar({ open, onClose, onChanged }) {
  const PRODUCTION_ID = getProductionId()
  const [columns, setColumns] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError]     = useState(null)
  const [editingId, setEditingId] = useState(null)
  const [form, setForm] = useState({
    header_label: '',
    source_field: '',
    width: '110px',
  })
  const [saving, setSaving] = useState(false)

  const catalogByCategory = getCatalogByCategory()

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  async function handleDragEnd(event) {
    const { active, over } = event
    if (!over || active.id === over.id) return
    const oldIdx = columns.findIndex(c => c.id === active.id)
    const newIdx = columns.findIndex(c => c.id === over.id)
    if (oldIdx === -1 || newIdx === -1) return
    const reordered = arrayMove(columns, oldIdx, newIdx)
    // Optimistic UI update
    setColumns(reordered)
    // Persist new display_order values: 10, 20, 30...
    try {
      await Promise.all(reordered.map((c, i) =>
        supabase
          .from('transport_list_columns')
          .update({ display_order: (i + 1) * 10, updated_at: new Date().toISOString() })
          .eq('id', c.id)
      ))
      onChanged?.()
    } catch (e) {
      setError('Reorder failed: ' + (e.message || 'unknown'))
      // Reload from DB to revert UI
      loadColumns()
    }
  }

  async function loadColumns() {
    if (!PRODUCTION_ID) return
    setLoading(true)
    const { data, error } = await supabase
      .from('transport_list_columns')
      .select('*')
      .eq('production_id', PRODUCTION_ID)
      .order('display_order', { ascending: true })
      .order('created_at', { ascending: true })
    if (error) setError(error.message)
    else setColumns(data || [])
    setLoading(false)
  }

  useEffect(() => { if (open) loadColumns() }, [open])

  function startEdit(c) {
    setEditingId(c.id)
    setForm({
      header_label: c.header_label,
      source_field: c.source_field,
      width:        c.width || '110px',
    })
    setError(null)
  }

  function cancelEdit() {
    setEditingId(null)
    setForm({ header_label: '', source_field: '', width: '110px' })
    setError(null)
  }

  function pickField(key) {
    const def = COLUMNS_CATALOG[key]
    if (!def) return
    setForm(f => ({
      ...f,
      source_field: key,
      header_label: f.header_label || def.label,
      width:        f.width || def.defaultWidth || '110px',
    }))
  }

  async function handleSave() {
    if (!form.header_label.trim() || !form.source_field) {
      setError('Header label and source field are required')
      return
    }
    if (!COLUMNS_CATALOG[form.source_field]) {
      setError('Unknown source field: ' + form.source_field)
      return
    }
    setSaving(true)
    setError(null)
    try {
      if (editingId) {
        const { error: e } = await supabase
          .from('transport_list_columns')
          .update({
            header_label: form.header_label.trim(),
            source_field: form.source_field,
            width:        form.width,
            updated_at:   new Date().toISOString(),
          })
          .eq('id', editingId)
        if (e) throw e
      } else {
        const nextOrder = columns.length > 0
          ? Math.max(...columns.map(c => c.display_order || 0)) + 10
          : 10
        const { error: e } = await supabase
          .from('transport_list_columns')
          .insert({
            production_id: PRODUCTION_ID,
            header_label: form.header_label.trim(),
            source_field: form.source_field,
            width:        form.width,
            display_order: nextOrder,
          })
        if (e) throw e
      }
      cancelEdit()
      await loadColumns()
      onChanged?.()
    } catch (e) {
      setError(e.message || 'Save failed')
    } finally {
      setSaving(false)
    }
  }

  async function handleDelete(c) {
    if (!confirm('Delete column "' + c.header_label + '"?')) return
    setError(null)
    const { error } = await supabase
      .from('transport_list_columns')
      .delete()
      .eq('id', c.id)
    if (error) { setError(error.message); return }
    await loadColumns()
    onChanged?.()
  }

  async function handleResetToCaptainPreset() {
    if (!PRODUCTION_ID) return
    if (columns.length > 0) {
      const ok = confirm('This will REPLACE all current columns with the Captain Preset (6 default columns). Continue?')
      if (!ok) return
    }
    setSaving(true)
    setError(null)
    try {
      if (columns.length > 0) {
        const { error: delErr } = await supabase
          .from('transport_list_columns')
          .delete()
          .eq('production_id', PRODUCTION_ID)
        if (delErr) throw delErr
      }
      const rows = CAPTAIN_PRESET.map(p => ({ ...p, production_id: PRODUCTION_ID }))
      const { error: insErr } = await supabase
        .from('transport_list_columns')
        .insert(rows)
      if (insErr) throw insErr
      cancelEdit()
      await loadColumns()
      onChanged?.()
    } catch (e) {
      setError(e.message || 'Reset failed')
    } finally {
      setSaving(false)
    }
  }

  const inp = { width: '100%', padding: '7px 10px', border: '1px solid #cbd5e1', borderRadius: '7px', fontSize: '13px', color: '#0f172a', background: 'white', boxSizing: 'border-box' }
  const lbl = { fontSize: '10px', fontWeight: '700', color: '#64748b', letterSpacing: '0.06em', textTransform: 'uppercase', display: 'block', marginBottom: '4px' }

  return (
    <>
      {open && <div onClick={onClose} style={{ position: 'fixed', inset: 0, zIndex: 40, background: 'rgba(15,35,64,0.15)' }} />}
      <div style={{
        position: 'fixed', top: 0, right: 0, bottom: 0,
        width: SIDEBAR_W + 'px', background: 'white',
        borderLeft: '1px solid #e2e8f0',
        boxShadow: '-4px 0 24px rgba(0,0,0,0.1)',
        zIndex: 50,
        transform: open ? 'translateX(0)' : 'translateX(' + SIDEBAR_W + 'px)',
        transition: 'transform 0.25s cubic-bezier(0.4,0,0.2,1)',
        display: 'flex', flexDirection: 'column',
      }}>
        {/* Header */}
        <div style={{ padding: '14px 18px', background: '#0f2340', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 }}>
          <div>
            <div style={{ fontSize: '10px', color: '#94a3b8', letterSpacing: '0.06em', textTransform: 'uppercase' }}>Customize</div>
            <div style={{ fontSize: '15px', fontWeight: '800', color: 'white' }}>Columns editor</div>
          </div>
          <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.15)', border: 'none', cursor: 'pointer', color: 'white', fontSize: '16px', lineHeight: 1, borderRadius: '6px', padding: '4px 8px' }}>x</button>
        </div>

        {/* Body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '14px 16px', display: 'flex', flexDirection: 'column', gap: '14px' }}>

          {/* Active columns list */}
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
              <div style={{ fontSize: '10px', fontWeight: '800', color: '#94a3b8', letterSpacing: '0.07em', textTransform: 'uppercase' }}>
                Active columns ({columns.length}) — drag ⋮⋮ to reorder
              </div>
              <button
                type="button"
                onClick={handleResetToCaptainPreset}
                disabled={saving}
                style={{ fontSize: '10px', padding: '3px 8px', borderRadius: '5px', border: '1px solid #2563eb', background: 'white', color: '#2563eb', cursor: saving ? 'default' : 'pointer', fontWeight: '700' }}>
                Reset to Captain Preset
              </button>
            </div>
            {loading ? (
              <div style={{ padding: '14px', textAlign: 'center', color: '#94a3b8', fontSize: '12px' }}>Loading...</div>
            ) : columns.length === 0 ? (
              <div style={{ padding: '14px', textAlign: 'center', color: '#cbd5e1', fontSize: '12px', fontStyle: 'italic', border: '1px dashed #e2e8f0', borderRadius: '7px' }}>
                No columns yet. Add one below or click &quot;Reset to Captain Preset&quot;.
              </div>
            ) : (
              <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={columns.map(c => c.id)} strategy={verticalListSortingStrategy}>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                    {columns.map(c => (
                      <SortableColumnRow
                        key={c.id}
                        column={c}
                        def={COLUMNS_CATALOG[c.source_field]}
                        isEditing={editingId === c.id}
                        onStartEdit={startEdit}
                        onCancelEdit={cancelEdit}
                        onDelete={handleDelete}
                      />
                    ))}
                  </div>
                </SortableContext>
              </DndContext>
            )}
          </div>

          {/* Add / Edit form */}
          <div style={{ border: '1px dashed #cbd5e1', borderRadius: '8px', padding: '10px 12px', background: '#f8fafc' }}>
            <div style={{ fontSize: '10px', fontWeight: '800', color: '#94a3b8', letterSpacing: '0.07em', textTransform: 'uppercase', marginBottom: '8px' }}>
              {editingId ? 'Edit column' : '+ Add new column'}
            </div>

            <div style={{ marginBottom: '8px' }}>
              <label style={lbl}>Source field (from DB)</label>
              <select
                value={form.source_field}
                onChange={e => pickField(e.target.value)}
                style={{ ...inp, fontSize: '12px' }}>
                <option value="">— Choose field —</option>
                {Object.entries(catalogByCategory).map(([cat, items]) => (
                  <optgroup key={cat} label={cat}>
                    {items.map(it => (
                      <option key={it.key} value={it.key}>{it.label}</option>
                    ))}
                  </optgroup>
                ))}
              </select>
            </div>

            <div style={{ marginBottom: '8px' }}>
              <label style={lbl}>Header label</label>
              <input
                type="text"
                value={form.header_label}
                onChange={e => setForm(f => ({ ...f, header_label: e.target.value }))}
                placeholder="e.g. Vehicle, Driver, Time..."
                style={inp} />
            </div>

            <div style={{ marginBottom: '10px' }}>
              <label style={lbl}>Width</label>
              <select
                value={form.width}
                onChange={e => setForm(f => ({ ...f, width: e.target.value }))}
                style={{ ...inp, fontSize: '12px' }}>
                {WIDTH_OPTIONS.map(w => (
                  <option key={w.value} value={w.value}>{w.label}</option>
                ))}
              </select>
            </div>

            <div style={{ display: 'flex', gap: '6px' }}>
              {editingId && (
                <button
                  type="button"
                  onClick={cancelEdit}
                  disabled={saving}
                  style={{ flex: 1, padding: '8px', borderRadius: '7px', border: '1px solid #e2e8f0', background: 'white', color: '#64748b', fontSize: '12px', fontWeight: '600', cursor: saving ? 'default' : 'pointer' }}>
                  Cancel
                </button>
              )}
              <button
                type="button"
                onClick={handleSave}
                disabled={saving || !form.header_label.trim() || !form.source_field}
                style={{
                  flex: 2,
                  padding: '8px', borderRadius: '7px', border: 'none',
                  background: (saving || !form.header_label.trim() || !form.source_field) ? '#cbd5e1' : '#2563eb',
                  color: 'white', fontSize: '13px', fontWeight: '800',
                  cursor: (saving || !form.header_label.trim() || !form.source_field) ? 'default' : 'pointer',
                }}>
                {saving ? 'Saving...' : (editingId ? 'Update column' : '+ Add column')}
              </button>
            </div>
          </div>

        </div>

        {error && <div style={{ margin: '0 16px 12px', padding: '8px 12px', background: '#fef2f2', border: '1px solid #fecaca', borderRadius: '7px', color: '#dc2626', fontSize: '12px' }}>Error: {error}</div>}

        {/* Footer */}
        <div style={{ padding: '12px 16px', borderTop: '1px solid #e2e8f0', flexShrink: 0, background: 'white' }}>
          <button
            type="button"
            onClick={onClose}
            style={{ width: '100%', padding: '9px', borderRadius: '8px', border: '1px solid #e2e8f0', background: 'white', color: '#64748b', fontSize: '13px', cursor: 'pointer', fontWeight: '600' }}>
            Close
          </button>
        </div>
      </div>
    </>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import {
  DndContext, closestCenter, KeyboardSensor, PointerSensor,
  useSensor, useSensors,
} from '@dnd-kit/core'
import {
  arrayMove, SortableContext, sortableKeyboardCoordinates,
  useSortable, verticalListSortingStrategy,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'

import { BLOCKS_CATALOG, getBlocksByZone, getBlockDef } from './tlBlocksCatalog'
import {
  loadActiveTemplate, applyTemplateToProduction,
  createTemplateFromPreset, listUserTemplates,
  addBlock as dbAddBlock, removeBlock as dbRemoveBlock,
  reorderBlocks as dbReorderBlocks,
  updateBlock as dbUpdateBlock,
} from './tlTemplatesDb'
import { BlockConfigForm, BlockConfigContext } from './BlockConfigForms'

// ─── Styles ──────────────────────────────────────────────────
const ZONE_BAR_COLORS = {
  header: '#1e293b',
  footer: '#475569',
}

// ─── Sortable block row ──────────────────────────────────────
function SortableBlockRow({ block, isExpanded, onToggle, onDelete, onPatch, productionId }) {
  const {
    attributes, listeners, setNodeRef, transform, transition, isDragging,
  } = useSortable({ id: block.id })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
  }

  const def = getBlockDef(block.block_type)
  const label = def?.label || block.block_type

  return (
    <div ref={setNodeRef} style={style}>
      <div
        onClick={onToggle}
        style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '8px 10px',
          background: isExpanded ? '#f1f5f9' : '#fafafa',
          border: '1px solid ' + (isExpanded ? '#cbd5e1' : '#e2e8f0'),
          borderRadius: 6,
          cursor: 'pointer',
          marginBottom: 4,
        }}
      >
        <span
          {...attributes}
          {...listeners}
          onClick={(e) => e.stopPropagation()}
          style={{
            cursor: 'grab', color: '#94a3b8', fontSize: 14,
            userSelect: 'none', padding: '0 4px',
          }}
          title="Drag to reorder"
        >
          ⋮⋮
        </span>
        <span style={{ flex: 1, fontSize: 13, fontWeight: 500, color: '#0f172a' }}>
          {label}
        </span>
        <span style={{ fontSize: 10, color: '#64748b', fontFamily: 'monospace' }}>
          {block.width}
        </span>
        <button
          onClick={(e) => { e.stopPropagation(); onDelete() }}
          style={{
            background: 'transparent', border: 'none', cursor: 'pointer',
            color: '#94a3b8', fontSize: 14, padding: '0 4px',
          }}
          title="Remove block"
        >
          ✕
        </button>
      </div>

      {isExpanded && (
        <div style={{
          padding: '12px',
          background: '#ffffff',
          border: '1px solid #cbd5e1',
          borderTop: 'none',
          borderRadius: '0 0 6px 6px',
          marginTop: -4,
          marginBottom: 8,
          fontSize: 12,
          color: '#475569',
        }}>
          <BlockConfigForm block={block} onPatch={onPatch} productionId={productionId} />
        </div>
      )}
    </div>
  )
}

// ─── Add-block dropdown ──────────────────────────────────────
function AddBlockDropdown({ zone, onAdd }) {
  const [open, setOpen] = useState(false)
  const byCategory = getBlocksByZone(zone)

  return (
    <div style={{ position: 'relative', marginTop: 8 }}>
      <button
        onClick={() => setOpen(o => !o)}
        style={{
          width: '100%', padding: '8px 12px',
          background: '#ffffff',
          border: '1px dashed #cbd5e1', borderRadius: 6,
          color: '#475569', fontSize: 12, fontWeight: 500,
          cursor: 'pointer',
        }}
      >
        + Add {zone} block
      </button>

      {open && (
        <div style={{
          position: 'absolute', top: '100%', left: 0, right: 0,
          marginTop: 4, zIndex: 10,
          background: '#ffffff',
          border: '1px solid #cbd5e1', borderRadius: 6,
          boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
          maxHeight: 300, overflowY: 'auto',
          padding: 6,
        }}>
          {Object.entries(byCategory).map(([category, items]) => (
            <div key={category} style={{ marginBottom: 8 }}>
              <div style={{
                fontSize: 10, fontWeight: 700, color: '#94a3b8',
                textTransform: 'uppercase', letterSpacing: 0.5,
                padding: '4px 8px',
              }}>
                {category}
              </div>
              {items.map(item => (
                <button
                  key={item.key}
                  onClick={() => { onAdd(item.key); setOpen(false) }}
                  style={{
                    display: 'block', width: '100%', textAlign: 'left',
                    padding: '6px 10px',
                    background: 'transparent', border: 'none',
                    color: '#0f172a', fontSize: 12,
                    cursor: 'pointer', borderRadius: 4,
                  }}
                  onMouseEnter={(e) => e.target.style.background = '#f1f5f9'}
                  onMouseLeave={(e) => e.target.style.background = 'transparent'}
                >
                  {item.label}
                </button>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Zone section (Header or Footer) ─────────────────────────
function ZoneSection({ zone, blocks, expandedId, setExpandedId, onReorder, onAdd, onDelete, onPatch, productionId }) {
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  )

  const handleDragEnd = (event) => {
    const { active, over } = event
    if (!over || active.id === over.id) return
    const oldIndex = blocks.findIndex(b => b.id === active.id)
    const newIndex = blocks.findIndex(b => b.id === over.id)
    if (oldIndex < 0 || newIndex < 0) return
    onReorder(arrayMove(blocks, oldIndex, newIndex))
  }

  const barColor = ZONE_BAR_COLORS[zone]

  return (
    <div style={{ marginBottom: 16 }}>
      <div style={{
        background: barColor, color: 'white',
        padding: '6px 12px', borderRadius: 4,
        fontSize: 11, fontWeight: 700,
        textTransform: 'uppercase', letterSpacing: 0.8,
        marginBottom: 10,
      }}>
        {zone}
      </div>

      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleDragEnd}
        onDragStart={() => setExpandedId(null)}
      >
        <SortableContext
          items={blocks.map(b => b.id)}
          strategy={verticalListSortingStrategy}
        >
          {blocks.length === 0 ? (
            <div style={{
              padding: 20, textAlign: 'center',
              color: '#94a3b8', fontSize: 11, fontStyle: 'italic',
              border: '1px dashed #e2e8f0', borderRadius: 6,
            }}>
              No blocks in {zone}
            </div>
          ) : (
            blocks.map(block => (
              <SortableBlockRow
                key={block.id}
                block={block}
                isExpanded={expandedId === block.id}
                onToggle={() => setExpandedId(expandedId === block.id ? null : block.id)}
                onDelete={() => onDelete(block.id)}
                onPatch={(patch) => onPatch(block.id, patch)}
                productionId={productionId}
              />
            ))
          )}
        </SortableContext>
      </DndContext>

      <AddBlockDropdown zone={zone} onAdd={onAdd} />
    </div>
  )
}

// ─── Main component ──────────────────────────────────────────
export function HeaderFooterEditorSidebar({ open, onClose, productionId, productionLabel = null }) {
  // ─── State ────────────────────────────────────────────────
  const [loading, setLoading] = useState(true)
  const [activeTemplate, setActiveTemplate] = useState(null)        // { id, name, blocks[] }
  const [productionTemplate, setProductionTemplate] = useState(null) // tl_production_template row
  const [userTemplates, setUserTemplates] = useState([])
  const [expandedId, setExpandedId] = useState(null)
  const [busy, setBusy] = useState(false)
  const [errorMsg, setErrorMsg] = useState(null)

  // Derived: blocks split by zone (always sorted)
  const allBlocks = activeTemplate?.blocks || []
  const headerBlocks = allBlocks
    .filter(b => b.zone === 'header')
    .sort((a, b) => (a.display_order || 0) - (b.display_order || 0))
  const footerBlocks = allBlocks
    .filter(b => b.zone === 'footer')
    .sort((a, b) => (a.display_order || 0) - (b.display_order || 0))

  // ─── Load ─────────────────────────────────────────────────
  const reload = useCallback(async () => {
    if (!productionId) return
    setLoading(true)
    setErrorMsg(null)
    try {
      const [active, tpls] = await Promise.all([
        loadActiveTemplate(productionId),
        listUserTemplates(),
      ])
      setActiveTemplate(active?.template || null)
      setProductionTemplate(active?.production_template || null)
      setUserTemplates(tpls)
    } catch (e) {
      console.error('[HeaderFooterEditor] reload error', e)
      setErrorMsg(e.message || String(e))
    } finally {
      setLoading(false)
    }
  }, [productionId])

  useEffect(() => {
    if (open && productionId) reload()
  }, [open, productionId, reload])

  // ─── Onboarding: create from preset ──────────────────────
  const handleCreateFromPreset = async () => {
    setBusy(true)
    setErrorMsg(null)
    try {
      const newTpl = await createTemplateFromPreset()
      await applyTemplateToProduction(productionId, newTpl.id, productionLabel)
      await reload()
    } catch (e) {
      console.error('[HeaderFooterEditor] createFromPreset error', e)
      setErrorMsg(e.message || String(e))
    } finally {
      setBusy(false)
    }
  }

  // ─── Apply existing template ──────────────────────────────
  const handleApplyTemplate = async (sourceTplId) => {
    if (!sourceTplId) return
    setBusy(true)
    setErrorMsg(null)
    try {
      await applyTemplateToProduction(productionId, sourceTplId, productionLabel)
      await reload()
    } catch (e) {
      console.error('[HeaderFooterEditor] applyTemplate error', e)
      setErrorMsg(e.message || String(e))
    } finally {
      setBusy(false)
    }
  }

  // ─── Block operations (now persistent) ────────────────────
  const addBlock = async (zone, blockType) => {
    if (!activeTemplate) return
    setBusy(true)
    setErrorMsg(null)
    try {
      await dbAddBlock(activeTemplate.id, zone, blockType)
      await reload()
    } catch (e) {
      console.error('[HeaderFooterEditor] addBlock error', e)
      setErrorMsg(e.message || String(e))
    } finally {
      setBusy(false)
    }
  }

  const deleteBlock = async (zone, id) => {
    setBusy(true)
    setErrorMsg(null)
    try {
      await dbRemoveBlock(id)
      if (expandedId === id) setExpandedId(null)
      await reload()
    } catch (e) {
      console.error('[HeaderFooterEditor] deleteBlock error', e)
      setErrorMsg(e.message || String(e))
    } finally {
      setBusy(false)
    }
  }

  // Optimistic patch: update local state immediately, then persist.
  // No `busy` spinner here — would feel laggy with debounced typing.
  const patchBlock = async (blockId, patch) => {
    setActiveTemplate(tpl => tpl ? ({
      ...tpl,
      blocks: tpl.blocks.map(b => b.id === blockId ? { ...b, ...patch } : b),
    }) : tpl)
    try {
      await dbUpdateBlock(blockId, patch)
    } catch (e) {
      console.error('[HeaderFooterEditor] patchBlock error', e)
      setErrorMsg(e.message || String(e))
      await reload()
    }
  }

  const reorderBlocksLocal = async (zone, newOrder) => {
    if (!activeTemplate) return
    // Optimistic update first
    const otherZone = zone === 'header' ? 'footer' : 'header'
    const reorderedWithOrder = newOrder.map((b, i) => ({ ...b, display_order: (i + 1) * 10 }))
    const otherBlocks = allBlocks.filter(b => b.zone === otherZone)
    setActiveTemplate(tpl => ({
      ...tpl,
      blocks: [...reorderedWithOrder, ...otherBlocks],
    }))
    // Then persist
    try {
      await dbReorderBlocks(activeTemplate.id, zone, newOrder.map(b => b.id))
    } catch (e) {
      console.error('[HeaderFooterEditor] reorder error', e)
      setErrorMsg(e.message || String(e))
      await reload()
    }
  }

  return (
    <BlockConfigContext.Provider value={{
      productionId,
      onAfterPersist: () => reload(),
    }}>
    <div
      style={{
        position: 'fixed', top: 0, right: 0, bottom: 0,
        width: 380,
        background: '#ffffff',
        borderLeft: '1px solid #e2e8f0',
        boxShadow: '-4px 0 12px rgba(0,0,0,0.04)',
        transform: open ? 'translateX(0)' : 'translateX(100%)',
        transition: 'transform 0.25s ease',
        zIndex: 100,
        display: 'flex', flexDirection: 'column',
      }}
    >
      {/* Header */}
      <div style={{
        padding: '14px 16px',
        borderBottom: '1px solid #e2e8f0',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      }}>
        <div>
          <div style={{ fontSize: 14, fontWeight: 700, color: '#0f172a' }}>
            Header &amp; Footer
          </div>
          {activeTemplate && (
            <div style={{ fontSize: 11, color: '#64748b', marginTop: 2 }}>
              Template: <span style={{ fontWeight: 600, color: '#334155' }}>{activeTemplate.name}</span>
            </div>
          )}
        </div>
        <button
          onClick={onClose}
          style={{
            background: 'transparent', border: 'none', cursor: 'pointer',
            fontSize: 18, color: '#64748b', padding: '4px 8px',
          }}
        >
          ✕
        </button>
      </div>

      {/* Template switcher row */}
      {activeTemplate && userTemplates.length > 0 && (
        <div style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e2e8f0',
          background: '#fafafa',
          display: 'flex', alignItems: 'center', gap: 8,
        }}>
          <label style={{ fontSize: 11, color: '#64748b', whiteSpace: 'nowrap' }}>
            Switch to:
          </label>
          <select
            value=""
            onChange={(e) => { if (e.target.value) handleApplyTemplate(e.target.value) }}
            disabled={busy}
            style={{
              flex: 1, fontSize: 11, padding: '4px 6px',
              border: '1px solid #cbd5e1', borderRadius: 4, background: '#ffffff',
            }}
          >
            <option value="">— pick a template —</option>
            {userTemplates
              .filter(t => t.id !== activeTemplate.id)
              .map(t => (
                <option key={t.id} value={t.id}>{t.name}</option>
              ))
            }
          </select>
        </div>
      )}

      {/* Error banner */}
      {errorMsg && (
        <div style={{
          padding: '8px 16px',
          background: '#fef2f2', color: '#991b1b',
          borderBottom: '1px solid #fecaca',
          fontSize: 11,
        }}>
          ⚠ {errorMsg}
        </div>
      )}

      {/* Body */}
      <div style={{
        flex: 1, overflowY: 'auto', padding: '16px',
        opacity: busy ? 0.5 : 1, pointerEvents: busy ? 'none' : 'auto',
      }}>
        {loading && (
          <div style={{ textAlign: 'center', color: '#94a3b8', fontSize: 12, padding: 24 }}>
            Loading…
          </div>
        )}

        {!loading && !activeTemplate && (
          <div style={{
            padding: 20, textAlign: 'center',
            border: '1px dashed #cbd5e1', borderRadius: 8,
            background: '#fafafa',
          }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#0f172a', marginBottom: 6 }}>
              No template active
            </div>
            <div style={{ fontSize: 11, color: '#64748b', marginBottom: 14, lineHeight: 1.5 }}>
              Create a template to define how the Transport List header
              and footer will look for this production.
            </div>
            <button
              onClick={handleCreateFromPreset}
              disabled={busy}
              style={{
                padding: '8px 16px',
                background: '#0f172a', color: '#ffffff',
                border: 'none', borderRadius: 6,
                fontSize: 12, fontWeight: 600, cursor: 'pointer',
                marginBottom: 8,
              }}
            >
              Create from Captain Template
            </button>
            {userTemplates.length > 0 && (
              <>
                <div style={{ fontSize: 10, color: '#94a3b8', margin: '8px 0' }}>
                  or use an existing template:
                </div>
                <select
                  value=""
                  onChange={(e) => { if (e.target.value) handleApplyTemplate(e.target.value) }}
                  disabled={busy}
                  style={{
                    width: '100%', fontSize: 11, padding: '6px 8px',
                    border: '1px solid #cbd5e1', borderRadius: 4,
                  }}
                >
                  <option value="">— pick a template —</option>
                  {userTemplates.map(t => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                  ))}
                </select>
              </>
            )}
          </div>
        )}

        {!loading && activeTemplate && (
          <>
            <ZoneSection
              zone="header"
              blocks={headerBlocks}
              expandedId={expandedId}
              setExpandedId={setExpandedId}
              onReorder={(newOrder) => reorderBlocksLocal('header', newOrder)}
              onAdd={(blockType) => addBlock('header', blockType)}
              onDelete={(id) => deleteBlock('header', id)}
              onPatch={patchBlock}
              productionId={productionId}
            />

            <ZoneSection
              zone="footer"
              blocks={footerBlocks}
              expandedId={expandedId}
              setExpandedId={setExpandedId}
              onReorder={(newOrder) => reorderBlocksLocal('footer', newOrder)}
              onAdd={(blockType) => addBlock('footer', blockType)}
              onDelete={(id) => deleteBlock('footer', id)}
              onPatch={patchBlock}
              productionId={productionId}
            />
          </>
        )}
      </div>
    </div>
    </BlockConfigContext.Provider>
  )
}

'use client'

/**
 * ImportModal — componente condiviso per import fleet/crew da file
 *
 * Props:
 *   open         — bool
 *   mode         — 'hal' | 'fleet' | 'crew' | 'custom' (modalità iniziale)
 *   productionId — UUID produzione attiva
 *   locations    — array { id, name } (per hotel matching crew)
 *   onClose      — function
 *   onImported   — function(result) chiamata dopo import completato
 *
 * State machine:
 *   idle → parsing → preview → confirming → done
 *
 * Modes:
 *   hal    — 🔴 HAL: Claude auto-rileva il tipo di documento
 *   crew   — 👥 Crew list: estrae first_name, last_name, role, dept, phone, email
 *   fleet  — 🚗 Fleet list: estrae driver, tipo, targa, sign_code, capacità
 *   custom — ✏️ Custom instructions: prompt libero
 */

import { useState, useRef, useEffect } from 'react'

// ── Helpers colori righe ────────────────────────────────────

function isUnrecognized(row, mode) {
  if (mode === 'fleet')         return !row.driver_name && !row.plate && !row.vehicle_type
  if (mode === 'crew')          return !row.first_name && !row.last_name
  if (mode === 'accommodation') return !row.existingId && !row.first_name && !row.last_name
  return false
}

function hasNullFields(row, mode) {
  if (mode === 'fleet')         return !row.driver_name || !row.plate || row.capacity == null
  if (mode === 'crew')          return !row.department || !row.role
  if (mode === 'accommodation') return !row.arrival_date || !row.departure_date
  return false
}

function rowBg(row, mode) {
  if (mode === 'accommodation') {
    if (row.action === 'skip')                    return '#f1f5f9'   // ⚫ grigio — saltato
    if (!row.arrival_date || !row.departure_date) return '#fefce8'   // 🟡 giallo — date mancanti
    return 'white'
  }
  if (isUnrecognized(row, mode))   return '#fef2f2'   // 🔴 rosso — non riconosciuto
  if (row.existingId)              return '#fff7ed'   // 🟠 arancione — duplicato
  if (row.active === false)        return '#f1f5f9'   // ⚫ grigio — not yet active
  if (hasNullFields(row, mode))    return '#fefce8'   // 🟡 giallo — campi mancanti
  return 'white'                                      // 🟢 bianco — ok
}

// ── Stili condivisi ─────────────────────────────────────────
const CELL_INPUT = {
  padding: '3px 6px',
  border: '1px solid #e2e8f0',
  borderRadius: '5px',
  fontSize: '12px',
  width: '100%',
  boxSizing: 'border-box',
  background: 'white',
  color: '#0f172a',
}

const TH = {
  padding: '8px 10px',
  textAlign: 'left',
  fontSize: '10px',
  fontWeight: '800',
  color: '#94a3b8',
  textTransform: 'uppercase',
  letterSpacing: '0.06em',
  borderBottom: '1px solid #e2e8f0',
  whiteSpace: 'nowrap',
}

// Defaults capacity/pax_suggested per tipo veicolo
const FLEET_DEFAULTS = { VAN: { capacity: 8, pax_suggested: 8 }, CAR: { capacity: 4, pax_suggested: 4 }, BUS: {} }

// Dipartimenti disponibili
const DEPTS = ['CAMERA','GRIP','ELECTRIC','SOUND','ART','COSTUME','MAKEUP','HMU','AD','PRODUCTION','TRANSPORT','PROPS','SET DEC','ACCOUNTING','PRODUCERS','CATERING','SECURITY','MEDICAL','VFX','DIRECTING','CAST','LOCATIONS','OTHER']

// ── Fleet preview table ─────────────────────────────────────
function FleetTable({ rows, onToggleAction, onEdit }) {
  return (
    <div style={{ overflowX: 'auto' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '12px' }}>
        <thead>
          <tr style={{ background: '#f8fafc' }}>
            <th style={TH}>Type</th>
            <th style={TH}>Driver</th>
            <th style={TH}>Plate</th>
            <th style={{ ...TH, textAlign: 'center' }}>Cap</th>
            <th style={{ ...TH, textAlign: 'center' }}>Pax sugg.</th>
            <th style={{ ...TH, textAlign: 'center' }}>Pax max</th>
            <th style={TH}>Sign</th>
            <th style={{ ...TH, textAlign: 'center' }}>Avail. From</th>
            <th style={{ ...TH, textAlign: 'center' }}>Avail. To</th>
            <th style={{ ...TH, textAlign: 'center' }}>Status</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((row) => (
            <tr key={row._idx} style={{ background: rowBg(row, 'fleet'), borderBottom: '1px solid #f1f5f9' }}>
              <td style={{ padding: '6px 10px' }}>
                <select
                  value={row.vehicle_type || 'VAN'}
                  onChange={e => onEdit(row._idx, 'vehicle_type', e.target.value)}
                  style={{ ...CELL_INPUT, width: '70px' }}
                >
                  <option>VAN</option>
                  <option>CAR</option>
                  <option>BUS</option>
                </select>
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  value={row.driver_name || ''}
                  onChange={e => onEdit(row._idx, 'driver_name', e.target.value || null)}
                  style={{ ...CELL_INPUT, minWidth: '130px' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  value={row.plate || ''}
                  onChange={e => onEdit(row._idx, 'plate', e.target.value.toUpperCase() || null)}
                  style={{ ...CELL_INPUT, fontFamily: 'monospace', fontWeight: '700', width: '100px' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  value={row.capacity ?? ''}
                  onChange={e => onEdit(row._idx, 'capacity', e.target.value !== '' ? parseInt(e.target.value) : null)}
                  style={{ ...CELL_INPUT, width: '50px', textAlign: 'center' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  value={row.pax_suggested ?? ''}
                  onChange={e => onEdit(row._idx, 'pax_suggested', e.target.value !== '' ? parseInt(e.target.value) : null)}
                  style={{ ...CELL_INPUT, width: '55px', textAlign: 'center' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  value={row.pax_max ?? ''}
                  onChange={e => onEdit(row._idx, 'pax_max', e.target.value !== '' ? parseInt(e.target.value) : null)}
                  style={{ ...CELL_INPUT, width: '55px', textAlign: 'center' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  value={row.sign_code || ''}
                  onChange={e => onEdit(row._idx, 'sign_code', e.target.value || null)}
                  style={{ ...CELL_INPUT, width: '80px' }}
                  placeholder="–"
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  type="date"
                  value={row.available_from || ''}
                  onChange={e => onEdit(row._idx, 'available_from', e.target.value || null)}
                  style={{ ...CELL_INPUT, width: '130px' }}
                />
              </td>
              <td style={{ padding: '6px 10px' }}>
                <input
                  type="date"
                  value={row.available_to || ''}
                  onChange={e => onEdit(row._idx, 'available_to', e.target.value || null)}
                  style={{ ...CELL_INPUT, width: '130px' }}
                />
              </td>
              <td style={{ padding: '6px 10px', textAlign: 'center' }}>
                {row.existingId ? (
                  <button
                    onClick={() => onToggleAction(row._idx)}
                    style={{
                      padding: '3px 8px', borderRadius: '999px', fontSize: '10px', fontWeight: '700',
                      cursor: 'pointer', border: '1px solid',
                      ...(row.action === 'update'
                        ? { background: '#fff7ed', color: '#c2410c', borderColor: '#fdba74' }
                        : { background: '#f1f5f9', color: '#64748b', borderColor: '#e2e8f0' }),
                    }}
                  >
                    {row.action === 'update' ? '🔄 Update' : '⏭ Skip'}
                  </button>
                ) : (
                  <span style={{ padding: '3px 8px', borderRadius: '999px', fontSize: '10px', fontWeight: '700', background: '#f0fdf4', color: '#15803d', border: '1px solid #86efac' }}>
                    ✅ New
                  </span>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

// ── Crew preview table ──────────────────────────────────────

