// ─── Editor field picker helpers ─────────────────────────────
// Used by the Header/Footer editor sidebar to group blocks by zone and category.

export function getBlocksByZone(zone) {
  const out = {}
  for (const [key, def] of Object.entries(BLOCKS_CATALOG)) {
    if (def.zone !== zone) continue
    if (!out[def.category]) out[def.category] = []
    out[def.category].push({
      key,
      label: def.label,
      defaultWidth: def.defaultWidth,
      defaultConfig: def.defaultConfig,
    })
  }
  return out
}

export function getBlockDef(blockType) {
  return BLOCKS_CATALOG[blockType] || null
}

export function renderBlock(blockType, config, ctx) {
  const def = BLOCKS_CATALOG[blockType]
  if (!def) return null
  return def.render(config || def.defaultConfig || {}, ctx || {})
}

'use client'

import { supabase } from './supabase'
import { CAPTAIN_TEMPLATE_PRESET, BLOCKS_CATALOG } from './tlBlocksCatalog'

// ─── Internal helpers ────────────────────────────────────────

async function getCurrentUserId() {
  const { data: { user }, error } = await supabase.auth.getUser()
  if (error || !user) throw new Error('Not authenticated')
  return user.id
}

function nextOrderInZone(blocks, zone) {
  const inZone = (blocks || []).filter(b => b.zone === zone)
  if (inZone.length === 0) return 10
  return Math.max(...inZone.map(b => b.display_order || 0)) + 10
}

// ─── TEMPLATES — Library CRUD ────────────────────────────────

/**
 * List all templates owned by the current user.
 * Returns: [{ id, name, description, is_default, created_at, updated_at }]
 */
export async function listUserTemplates() {
  const userId = await getCurrentUserId()
  const { data, error } = await supabase
    .from('tl_templates')
    .select('id, name, description, is_default, created_at, updated_at')
    .eq('owner_user_id', userId)
    .order('updated_at', { ascending: false })
  if (error) throw error
  return data || []
}

/**
 * Load a single template with all its blocks.
 * Returns: { ...template, blocks: [...] }
 */
export async function loadTemplate(templateId) {
  const { data: tpl, error: tplErr } = await supabase
    .from('tl_templates')
    .select('*')
    .eq('id', templateId)
    .single()
  if (tplErr) throw tplErr

  const { data: blocks, error: blocksErr } = await supabase
    .from('tl_template_blocks')
    .select('*')
    .eq('template_id', templateId)
    .order('display_order', { ascending: true })
  if (blocksErr) throw blocksErr

  return { ...tpl, blocks: blocks || [] }
}

/**
 * Create a blank template (no blocks).
 */
export async function createBlankTemplate(name, description = null) {
  const userId = await getCurrentUserId()
  const { data, error } = await supabase
    .from('tl_templates')
    .insert({ owner_user_id: userId, name, description })
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Create a template from the hardcoded Captain Template preset.
 * Inserts the template row and all its blocks atomically.
 */
export async function createTemplateFromPreset(customName = null) {
  const userId = await getCurrentUserId()
  const preset = CAPTAIN_TEMPLATE_PRESET

  // 1) Create template row
  const { data: tpl, error: tplErr } = await supabase
    .from('tl_templates')
    .insert({
      owner_user_id: userId,
      name: customName || preset.name,
      description: preset.description,
    })
    .select()
    .single()
  if (tplErr) throw tplErr

  // 2) Insert blocks
  const blocksToInsert = preset.blocks.map(b => ({
    template_id: tpl.id,
    zone: b.zone,
    display_order: b.display_order,
    block_type: b.block_type,
    config: b.config,
    width: b.width,
  }))
  const { data: blocks, error: blocksErr } = await supabase
    .from('tl_template_blocks')
    .insert(blocksToInsert)
    .select()
  if (blocksErr) {
    // Best-effort rollback: delete the template row
    await supabase.from('tl_templates').delete().eq('id', tpl.id)
    throw blocksErr
  }

  return { ...tpl, blocks: blocks || [] }
}

/**
 * Duplicate an existing template (deep copy: template + blocks).
 */
export async function duplicateTemplate(sourceTemplateId, newName = null) {
  const userId = await getCurrentUserId()
  const source = await loadTemplate(sourceTemplateId)

  const { data: tpl, error: tplErr } = await supabase
    .from('tl_templates')
    .insert({
      owner_user_id: userId,
      name: newName || `${source.name} (copy)`,
      description: source.description,
    })
    .select()
    .single()
  if (tplErr) throw tplErr

  if (source.blocks.length > 0) {
    const blocksToInsert = source.blocks.map(b => ({
      template_id: tpl.id,
      zone: b.zone,
      display_order: b.display_order,
      block_type: b.block_type,
      config: b.config,
      width: b.width,
    }))
    const { error: blocksErr } = await supabase
      .from('tl_template_blocks')
      .insert(blocksToInsert)
    if (blocksErr) {
      await supabase.from('tl_templates').delete().eq('id', tpl.id)
      throw blocksErr
    }
  }

  return await loadTemplate(tpl.id)
}

/**
 * Rename a template.
 */
export async function renameTemplate(templateId, newName) {
  const { data, error } = await supabase
    .from('tl_templates')
    .update({ name: newName })
    .eq('id', templateId)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Delete a template (cascades to blocks).
 * If any production has this template_id, the production_template.template_id
 * becomes NULL (ON DELETE SET NULL).
 */
export async function deleteTemplate(templateId) {
  const { error } = await supabase
    .from('tl_templates')
    .delete()
    .eq('id', templateId)
  if (error) throw error
  return { ok: true }
}

// ─── BLOCKS — CRUD inside a template ─────────────────────────

/**
 * Add a new block to a template.
 * Pulls defaultConfig from BLOCKS_CATALOG if not provided.
 */
export async function addBlock(templateId, zone, blockType, opts = {}) {
  const def = BLOCKS_CATALOG[blockType]
  if (!def) throw new Error(`Unknown block_type: ${blockType}`)
  if (def.zone !== zone) {
    throw new Error(`Block ${blockType} belongs to zone ${def.zone}, not ${zone}`)
  }

  // compute next display_order
  const { data: existing } = await supabase
    .from('tl_template_blocks')
    .select('display_order')
    .eq('template_id', templateId)
    .eq('zone', zone)
    .order('display_order', { ascending: false })
    .limit(1)

  const nextOrder = (existing && existing[0]?.display_order || 0) + 10

  const { data, error } = await supabase
    .from('tl_template_blocks')
    .insert({
      template_id: templateId,
      zone,
      block_type: blockType,
      display_order: opts.display_order ?? nextOrder,
      config: opts.config || def.defaultConfig || {},
      width: opts.width || def.defaultWidth || '1fr',
    })
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Update a block's config / width / display_order.
 * Pass only the fields you want to change in `patch`.
 */
export async function updateBlock(blockId, patch) {
  const allowed = ['config', 'width', 'display_order']
  const payload = {}
  for (const k of allowed) if (k in patch) payload[k] = patch[k]
  if (Object.keys(payload).length === 0) {
    throw new Error('updateBlock: nothing to update')
  }
  const { data, error } = await supabase
    .from('tl_template_blocks')
    .update(payload)
    .eq('id', blockId)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Delete a block.
 */
export async function removeBlock(blockId) {
  const { error } = await supabase
    .from('tl_template_blocks')
    .delete()
    .eq('id', blockId)
  if (error) throw error
  return { ok: true }
}

/**
 * Reorder all blocks in a zone in one shot.
 * orderedIds = array of block UUIDs in the new order.
 * Assigns display_order = 10, 20, 30...
 */
export async function reorderBlocks(templateId, zone, orderedIds) {
  if (!Array.isArray(orderedIds)) throw new Error('orderedIds must be an array')
  const updates = orderedIds.map((id, idx) =>
    supabase
      .from('tl_template_blocks')
      .update({ display_order: (idx + 1) * 10 })
      .eq('id', id)
      .eq('template_id', templateId)
      .eq('zone', zone)
  )
  const results = await Promise.all(updates)
  for (const r of results) {
    if (r.error) throw r.error
  }
  return { ok: true, count: orderedIds.length }
}

// ─── PRODUCTION ↔ TEMPLATE (snapshot via duplication) ────────

/**
 * Load the template currently active on a production, with all its blocks
 * and the production-level overrides + logo path.
 * Returns null if no template applied.
 *
 * Returns: {
 *   production_template: { id, production_id, template_id, overrides, logo_storage_path },
 *   template: { id, name, description, ... , blocks: [...] }
 * } | null
 */
export async function loadActiveTemplate(productionId) {
  const { data: pt, error: ptErr } = await supabase
    .from('tl_production_template')
    .select('*')
    .eq('production_id', productionId)
    .maybeSingle()
  if (ptErr) throw ptErr
  if (!pt || !pt.template_id) return null

  const template = await loadTemplate(pt.template_id)
  return { production_template: pt, template }
}

/**
 * Apply a template to a production.
 *
 * Behavior (snapshot via duplication):
 *   1. Duplicates the source template into the user's library
 *      with name "<source name> — <productionName or productionId>"
 *   2. Upserts tl_production_template to point to the new duplicated template.
 *   3. Resets overrides to {} (snapshot is fresh).
 *
 * This means modifying the source template AFTER apply does NOT affect
 * the production. The production now owns its own duplicated template.
 *
 * To re-pull changes later, the user can call applyTemplateToProduction()
 * again with the same sourceTemplateId — this will replace the snapshot.
 */
export async function applyTemplateToProduction(productionId, sourceTemplateId, productionLabel = null) {
  const source = await loadTemplate(sourceTemplateId)
  const newName = productionLabel
    ? `${source.name} — ${productionLabel}`
    : `${source.name} — applied`
  const duplicated = await duplicateTemplate(sourceTemplateId, newName)

  // Upsert production_template
  const { data: existing } = await supabase
    .from('tl_production_template')
    .select('id, template_id')
    .eq('production_id', productionId)
    .maybeSingle()

  let result
  if (existing) {
    const oldTemplateId = existing.template_id
    const { data, error } = await supabase
      .from('tl_production_template')
      .update({
        template_id: duplicated.id,
        overrides: {},
      })
      .eq('production_id', productionId)
      .select()
      .single()
    if (error) throw error
    result = data
    // Best-effort cleanup of the previous snapshot if it looked like an applied copy
    // (i.e. name ends with " — applied" or " — <label>"). We don't delete user-named
    // templates from the library.
    if (oldTemplateId && oldTemplateId !== duplicated.id) {
      const { data: oldTpl } = await supabase
        .from('tl_templates')
        .select('name')
        .eq('id', oldTemplateId)
        .maybeSingle()
      if (oldTpl?.name && / — /.test(oldTpl.name)) {
        await supabase.from('tl_templates').delete().eq('id', oldTemplateId)
      }
    }
  } else {
    const { data, error } = await supabase
      .from('tl_production_template')
      .insert({
        production_id: productionId,
        template_id: duplicated.id,
        overrides: {},
      })
      .select()
      .single()
    if (error) throw error
    result = data
  }

  return { production_template: result, template: duplicated }
}

/**
 * Detach the current template from a production (without deleting it).
 */
export async function detachTemplateFromProduction(productionId) {
  const { error } = await supabase
    .from('tl_production_template')
    .update({ template_id: null, overrides: {} })
    .eq('production_id', productionId)
  if (error) throw error
  return { ok: true }
}

/**
 * Patch the production-level overrides JSON (merges with existing).
 * overrides shape: { [blockId]: { config?: {...}, width?: '...' } }
 */
export async function setProductionOverride(productionId, blockId, patch) {
  const { data: pt } = await supabase
    .from('tl_production_template')
    .select('overrides')
    .eq('production_id', productionId)
    .single()
  const current = pt?.overrides || {}
  const merged = { ...current, [blockId]: { ...(current[blockId] || {}), ...patch } }
  const { data, error } = await supabase
    .from('tl_production_template')
    .update({ overrides: merged })
    .eq('production_id', productionId)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Clear override for a single block on a production.
 */
export async function clearProductionOverride(productionId, blockId) {
  const { data: pt } = await supabase
    .from('tl_production_template')
    .select('overrides')
    .eq('production_id', productionId)
    .single()
  const current = pt?.overrides || {}
  // eslint-disable-next-line no-unused-vars
  const { [blockId]: _, ...rest } = current
  const { data, error } = await supabase
    .from('tl_production_template')
    .update({ overrides: rest })
    .eq('production_id', productionId)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Set the logo storage path on the production_template.
 * The actual file upload to the `tl-logos` bucket is handled separately.
 */
export async function setLogoStoragePath(productionId, storagePath) {
  const { data, error } = await supabase
    .from('tl_production_template')
    .update({ logo_storage_path: storagePath })
    .eq('production_id', productionId)
    .select()
    .single()
  if (error) throw error
  return data
}

// ─── LOGO Storage helpers ────────────────────────────────────

const LOGO_BUCKET = 'tl-logos'

/**
 * Upload a logo Blob/File to Supabase Storage for the given production.
 * Path: {productionId}/logo.{ext}
 * Always uses upsert: a new upload replaces the previous logo.
 *
 * Returns the storage path (string) that was written.
 */
export async function uploadProductionLogo(productionId, blob, extension) {
  if (!productionId) throw new Error('uploadProductionLogo: productionId is required')
  const path = `${productionId}/logo.${extension}`

  // 1) Upload (upsert)
  const { error: upErr } = await supabase.storage
    .from(LOGO_BUCKET)
    .upload(path, blob, {
      cacheControl: '3600',
      upsert: true,
      contentType: blob.type || `image/${extension === 'jpg' ? 'jpeg' : extension}`,
    })
  if (upErr) throw upErr

  // 2) Clean up any other logo files with different extensions for this production
  //    (e.g. user uploaded a PNG before, then a JPG — remove the PNG)
  const { data: list } = await supabase.storage
    .from(LOGO_BUCKET)
    .list(productionId, { limit: 100 })
  if (list && list.length > 0) {
    const toRemove = list
      .filter(f => f.name.startsWith('logo.') && f.name !== `logo.${extension}`)
      .map(f => `${productionId}/${f.name}`)
    if (toRemove.length > 0) {
      await supabase.storage.from(LOGO_BUCKET).remove(toRemove)
    }
  }

  // 3) Update tl_production_template.logo_storage_path
  await setLogoStoragePath(productionId, path)

  return path
}

/**
 * Delete the current logo of a production from Storage and clear the DB pointer.
 */
export async function deleteProductionLogo(productionId) {
  if (!productionId) throw new Error('deleteProductionLogo: productionId is required')

  // List and remove all files under {productionId}/
  const { data: list } = await supabase.storage
    .from(LOGO_BUCKET)
    .list(productionId, { limit: 100 })
  if (list && list.length > 0) {
    const paths = list.map(f => `${productionId}/${f.name}`)
    await supabase.storage.from(LOGO_BUCKET).remove(paths)
  }

  // Clear DB pointer
  await setLogoStoragePath(productionId, null)

  return { ok: true }
}

/**
 * Get a signed URL for the current logo of a production.
 * Returns null if no logo is set.
 * Signed URL expires in 1 hour.
 */
export async function getProductionLogoUrl(productionId) {
  if (!productionId) return null
  const { data: pt } = await supabase
    .from('tl_production_template')
    .select('logo_storage_path')
    .eq('production_id', productionId)
    .maybeSingle()
  const path = pt?.logo_storage_path
  if (!path) return null
  const { data, error } = await supabase.storage
    .from(LOGO_BUCKET)
    .createSignedUrl(path, 3600)
  if (error) {
    console.error('[getProductionLogoUrl] signed URL error', error)
    return null
  }
  return data?.signedUrl || null
}

// ─── TEAM CONTACTS (explicit add via autocomplete + overrides) ─

/**
 * Search crew members by full_name for autocomplete.
 * Returns up to `limit` rows.
 * Excludes crew that are already added to the production's team contacts list.
 */
export async function searchCrewForContacts(productionId, query, excludeCrewIds = []) {
  if (!productionId) return []
  const q = (query || '').trim()
  if (q.length < 1) return []

  let req = supabase
    .from('crew')
    .select('id, full_name, role, department, phone, email')
    .eq('production_id', productionId)
    .ilike('full_name', `%${q}%`)
    .order('full_name', { ascending: true })
    .limit(15)

  const { data, error } = await req
  if (error) throw error

  const list = data || []
  // Client-side filter for excluded (Supabase .not('id','in', ...) requires
  // comma-separated string and gets messy with special chars)
  if (excludeCrewIds.length > 0) {
    const skip = new Set(excludeCrewIds)
    return list.filter(c => !skip.has(c.id))
  }
  return list
}

/**
 * Load the resolved list of team contacts for a production.
 *
 * Logic:
 *   - For each row in tl_team_contacts_overrides where crew_id IS NOT NULL:
 *     - If syncWithCrew is true → re-read live crew data, fall back to override
 *       fields if any is set
 *     - If syncWithCrew is false → use override fields as snapshot
 *   - For each row where crew_id IS NULL: it's a manual contact, use override fields
 *
 * @param {string} productionId
 * @param {boolean} syncWithCrew — pulled from block config (autoFromDB toggle)
 */
export async function loadResolvedTeamContacts(productionId, syncWithCrew = true) {
  if (!productionId) return []

  // 1) Get all override rows for this production
  const { data: overrides, error: ovErr } = await supabase
    .from('tl_team_contacts_overrides')
    .select('*')
    .eq('production_id', productionId)
    .order('display_order', { ascending: true })
  if (ovErr) throw ovErr

  if (!overrides || overrides.length === 0) return []

  // 2) If syncWithCrew, fetch the linked crew rows
  let crewById = {}
  if (syncWithCrew) {
    const crewIds = overrides.filter(o => o.crew_id).map(o => o.crew_id)
    if (crewIds.length > 0) {
      const { data: crew } = await supabase
        .from('crew')
        .select('id, full_name, role, department, phone, email')
        .in('id', crewIds)
      for (const c of (crew || [])) crewById[c.id] = c
    }
  }

  // 3) Resolve each override row
  return overrides.map(ov => {
    const c = ov.crew_id ? crewById[ov.crew_id] : null
    // When syncing and crew exists, prefer live crew data;
    // but if user explicitly overrode a field (override value present),
    // the override wins regardless of sync mode.
    return {
      key: ov.crew_id ? 'crew:' + ov.crew_id : 'manual:' + ov.id,
      crew_id: ov.crew_id,
      override_id: ov.id,
      name:  ov.name_override  || (c ? (c.full_name || '') : ''),
      role:  ov.role_override  || (c ? (c.role || c.department || '') : ''),
      phone: ov.phone_override || (c ? (c.phone || '') : ''),
      email: ov.email_override || (c ? (c.email || '') : ''),
      hidden: ov.hidden || false,
      display_order: ov.display_order || 100,
    }
  })
}

/**
 * Add a crew-linked contact to the team list.
 * If syncWithCrew is OFF, snapshots the current crew data into the override row.
 * Otherwise leaves override fields empty so live crew data is used.
 */
export async function addCrewContact(productionId, crew, opts = {}) {
  if (!productionId || !crew?.id) throw new Error('productionId and crew object required')
  const { snapshotData = false, display_order = 100 } = opts

  // Check if already exists
  const { data: existing } = await supabase
    .from('tl_team_contacts_overrides')
    .select('id')
    .eq('production_id', productionId)
    .eq('crew_id', crew.id)
    .maybeSingle()
  if (existing) return existing // idempotent

  const payload = {
    production_id: productionId,
    crew_id: crew.id,
    hidden: false,
    display_order,
  }
  if (snapshotData) {
    payload.name_override  = crew.full_name || ''
    payload.role_override  = crew.role || crew.department || ''
    payload.phone_override = crew.phone || ''
    payload.email_override = crew.email || ''
  }

  const { data, error } = await supabase
    .from('tl_team_contacts_overrides')
    .insert(payload)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Add a manual contact (not linked to any crew).
 */
export async function addManualContact(productionId, contact = {}) {
  if (!productionId) throw new Error('productionId required')
  const { data, error } = await supabase
    .from('tl_team_contacts_overrides')
    .insert({
      production_id: productionId,
      crew_id: null,
      name_override:  contact.name  || '',
      role_override:  contact.role  || '',
      phone_override: contact.phone || '',
      email_override: contact.email || '',
      hidden: false,
      display_order: contact.display_order ?? 500,
    })
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Update any field on an override row.
 */
export async function updateContactOverride(overrideId, patch) {
  const allowed = ['name_override','role_override','phone_override','email_override','hidden','display_order']
  const payload = {}
  for (const k of allowed) if (k in patch) payload[k] = patch[k]
  if (Object.keys(payload).length === 0) return null
  const { data, error } = await supabase
    .from('tl_team_contacts_overrides')
    .update(payload)
    .eq('id', overrideId)
    .select()
    .single()
  if (error) throw error
  return data
}

/**
 * Delete an override row → removes the contact from the team list.
 */
export async function deleteContactOverride(overrideId) {
  const { error } = await supabase
    .from('tl_team_contacts_overrides')
    .delete()
    .eq('id', overrideId)
  if (error) throw error
  return { ok: true }
}

#!/usr/bin/env node
/**
 * scripts/import-from-sheets.js
 *
 * One-time import: Excel (Google Sheets export) → Supabase
 * Importa: Hotels + Hubs → locations, Fleet → vehicles, Crew_Master → crew,
 *          Routes → routes, Lists(Service_Type) → service_types, Trips → trips + trip_passengers
 *
 * Usage:
 *   node scripts/import-from-sheets.js "C:\Users\WKS\Downloads\Captain by Daniele Contino 21_03 (6).xlsx"
 *
 * IMPORTANTE — RLS bypass:
 *   Con la ANON KEY le INSERT falliscono se RLS è abilitato.
 *   Aggiungi a .env.local:  SUPABASE_SERVICE_ROLE_KEY=eyJ...
 *   Trovala in: Supabase Dashboard → Settings → API → service_role (secret)
 *
 *   In alternativa, per il tempo dell'import:
 *   Supabase Dashboard → Table Editor → ogni tabella → Auth → Disable RLS
 */

'use strict'

const XLSX   = require('xlsx')
const { createClient } = require('@supabase/supabase-js')
const fs     = require('fs')
const path   = require('path')

// ─────────────────────────────────────────────
// 1. CARICA ENV
// ─────────────────────────────────────────────
function loadEnv () {
  const envPath = path.join(__dirname, '..', '.env.local')
  if (!fs.existsSync(envPath)) throw new Error('.env.local non trovato in ' + path.dirname(envPath))
  const env = {}
  // Rimuove BOM UTF-8 (\uFEFF) e normalizza CRLF → LF
  const content = fs.readFileSync(envPath, 'utf8')
    .replace(/^\uFEFF/, '')   // strip BOM
    .replace(/\r\n/g, '\n')   // CRLF → LF
    .replace(/\r/g, '\n')     // CR → LF
  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed || trimmed.startsWith('#')) continue
    const eqIdx = trimmed.indexOf('=')
    if (eqIdx === -1) continue
    const key = trimmed.slice(0, eqIdx).trim()
    const val = trimmed.slice(eqIdx + 1).trim()
    if (key) env[key] = val
  }
  return env
}

// ─────────────────────────────────────────────
// 2. UTILITY DATE / TIME
// ─────────────────────────────────────────────

/** Converte un valore cella Excel in stringa ISO date "YYYY-MM-DD", null se non valido */
function toISODate (val) {
  if (val instanceof Date) {
    const y = val.getUTCFullYear()
    if (y < 1900 || y > 2100) return null
    const m = String(val.getUTCMonth() + 1).padStart(2, '0')
    const d = String(val.getUTCDate()).padStart(2, '0')
    return `${y}-${m}-${d}`
  }
  if (typeof val === 'string') {
    const m = val.match(/^(\d{4}-\d{2}-\d{2})/)
    if (m) {
      const y = parseInt(m[1])
      if (y >= 1900 && y <= 2100) return m[1]
    }
  }
  return null
}

/** Converte un valore cella Excel in minuti dalla mezzanotte (0-1439), null se non valido */
function toMinutes (val) {
  if (val instanceof Date) {
    const h = val.getUTCHours()
    const m = val.getUTCMinutes()
    // 1899-12-30 = serial 0 in Excel = midnight (00:00) — potrebbe essere una cella vuota
    if (val.getUTCFullYear() === 1899) return h * 60 + m  // 0 = mezzanotte
    // Per datetime completo (data reale), estrai solo la parte oraria
    return h * 60 + m
  }
  if (typeof val === 'string') {
    const m = val.match(/^(\d{1,2}):(\d{2})/)
    if (m) return parseInt(m[1]) * 60 + parseInt(m[2])
  }
  return null
}

/** Converte un valore cella Excel in timestamp ISO (con data), null se non valido */
function toTimestamp (val, fallbackDate) {
  if (val instanceof Date) {
    const y = val.getUTCFullYear()
    if (y < 1900 || y > 2100) return null
    // Se è 1899 è solo un'orario senza data — combina con fallbackDate
    if (y === 1899 && fallbackDate) {
      const h = String(val.getUTCHours()).padStart(2, '0')
      const mi = String(val.getUTCMinutes()).padStart(2, '0')
      return `${fallbackDate}T${h}:${mi}:00+00:00`
    }
    return val.toISOString()
  }
  return null
}

/** Converte "10:00" → "10:00:00" per colonna TIME di Postgres */
function toTimeString (val) {
  if (val instanceof Date) {
    const h = String(val.getUTCHours()).padStart(2, '0')
    const m = String(val.getUTCMinutes()).padStart(2, '0')
    return `${h}:${m}:00`
  }
  if (typeof val === 'string') {
    const m = val.match(/^(\d{1,2}):(\d{2})/)
    if (m) return `${m[1].padStart(2, '0')}:${m[2]}:00`
  }
  return null
}

/** Null-safe string trim */
function str (val) {
  return (val === null || val === undefined) ? null : String(val).trim() || null
}

/** Null-safe integer */
function int (val) {
  if (val === null || val === undefined || val === '') return null
  const n = parseInt(val)
  return isNaN(n) ? null : n
}

// ─────────────────────────────────────────────
// 3. LEGGI FOGLIO EXCEL
// ─────────────────────────────────────────────
function readSheet (wb, sheetName) {
  const ws = wb.Sheets[sheetName]
  if (!ws) {
    console.warn(`  ⚠️  Foglio "${sheetName}" non trovato — saltato`)
    return []
  }
  return XLSX.utils.sheet_to_json(ws, { defval: null })
  // defval: null → celle vuote = null
  // cellDates: true è a livello di wb, quindi Date objects arrivano già qui
}

// ─────────────────────────────────────────────
// 4. ADAPTIVE UPSERT HELPER
// Rimuove automaticamente le colonne non presenti nello schema e riprova
// ─────────────────────────────────────────────
async function upsert (supabase, table, rows, conflictCol, label) {
  if (rows.length === 0) { console.log(`  ⏭  ${label}: nessun dato`); return }

  let currentRows = rows.map(r => ({ ...r }))  // copia per non modificare originali
  const skippedCols = []

  for (let attempt = 0; attempt < 15; attempt++) {
    // Prova upsert
    let res = await supabase
      .from(table)
      .upsert(currentRows, { onConflict: conflictCol, ignoreDuplicates: false })

    if (!res.error) {
      if (skippedCols.length > 0) {
        console.log(`  ✅ ${label}: ${currentRows.length} righe (colonne saltate: ${skippedCols.join(', ')})`)
      } else {
        console.log(`  ✅ ${label}: ${currentRows.length} righe`)
      }
      return
    }

    // Controlla se è un errore di colonna non scrivibile (mancante, GENERATED, ecc.)
    const colMatch =
      res.error.message.match(/Could not find the '([^']+)' column/) ||
      res.error.message.match(/cannot insert a non-DEFAULT value into column "([^"]+)"/) ||
      res.error.message.match(/column "([^"]+)" of relation "[^"]+" does not exist/) ||
      res.error.message.match(/cannot set an? \w+ column "([^"]+)"/)
    if (colMatch) {
      const missingCol = colMatch[1]
      skippedCols.push(missingCol)
      currentRows = currentRows.map(r => {
        const copy = { ...r }
        delete copy[missingCol]
        return copy
      })
      continue
    }

    // Errore di constraint mancante per upsert → fallback a insert ignorando duplicati
    if (res.error.message.includes('there is no unique or exclusion constraint') ||
        res.error.message.includes('onConflict')) {
      const { error: insertErr } = await supabase
        .from(table).insert(currentRows, { ignoreDuplicates: true })
      if (!insertErr) {
        if (skippedCols.length > 0) {
          console.log(`  ✅ ${label}: ${currentRows.length} righe (insert, colonne saltate: ${skippedCols.join(', ')})`)
        } else {
          console.log(`  ✅ ${label}: ${currentRows.length} righe (insert)`)
        }
        return
      }
      // Se anche insert fallisce per colonne, continua il loop
      const ic = insertErr.message.match(/Could not find the '([^']+)' column/)
      if (ic) {
        const mc = ic[1]
        skippedCols.push(mc)
        currentRows = currentRows.map(r => { const c = { ...r }; delete c[mc]; return c })
        continue
      }
      res.error = insertErr
    }

    // Errore genuino (non di schema)
    console.error(`  ❌ ${label}: ${res.error.message}`)
    if (res.error.message.includes('row-level security') || res.error.message.includes('RLS')) {
      console.error('     → La SERVICE_ROLE_KEY è necessaria per bypassare RLS')
    }
    throw res.error
  }

  throw new Error(`${label}: impossibile inserire dopo 15 tentativi di adattamento schema`)
}

// ─────────────────────────────────────────────
// 5. MAIN
// ─────────────────────────────────────────────
async function main () {
  const xlsxPath = process.argv[2]
  if (!xlsxPath) {
    console.error('Uso: node scripts/import-from-sheets.js <path-to-xlsx>')
    process.exit(1)
  }
  if (!fs.existsSync(xlsxPath)) {
    console.error('File non trovato:', xlsxPath)
    process.exit(1)
  }

  // Credenziali
  const env = loadEnv()
  const SUPABASE_URL = env['NEXT_PUBLIC_SUPABASE_URL']
  const SUPABASE_KEY = env['SUPABASE_SERVICE_ROLE_KEY'] || env['NEXT_PUBLIC_SUPABASE_ANON_KEY']
  if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Credenziali Supabase mancanti in .env.local')
  if (!env['SUPABASE_SERVICE_ROLE_KEY']) {
    console.warn('\n⚠️  Usando ANON KEY — se le insert falliscono, aggiungi SUPABASE_SERVICE_ROLE_KEY a .env.local\n')
  }

  const supabase = createClient(SUPABASE_URL, SUPABASE_KEY)

  // Leggi Excel
  console.log('📂 Lettura:', xlsxPath)
  const wb = XLSX.readFile(xlsxPath, { cellDates: true })

  // ── 5.1 PRODUCTION ────────────────────────────────────────────────────────
  console.log('\n[1/7] Productions...')
  const PROD_NAME = 'Captain Project — Palermo 2026'
  const PROD_SLUG = 'palermo-2026'
  let productionId

  // Helper: errore da colonna mancante (schema cache) — non è un errore reale
  const isSchemaErr = (e) => e && (
    e.message.includes('schema cache') ||
    e.message.includes('Could not find') ||
    e.message.includes('column') ||
    e.message.includes('violates not-null')
  )

  // 1) Cerca prima per nome (funziona sempre indipendentemente dallo schema)
  const { data: byName } = await supabase
    .from('productions').select('id').eq('name', PROD_NAME).maybeSingle()

  if (byName) {
    productionId = byName.id
    console.log(`  ♻️  Production trovata: ${productionId}`)
  } else {
    // 2) Tenta insert con payload progressivamente più semplice
    //    Ordine: schema nuovo (slug) → schema con code → solo name
    const payloads = [
      { name: PROD_NAME, slug: PROD_SLUG },
      { name: PROD_NAME, code: PROD_SLUG },
      { name: PROD_NAME },
    ]
    let inserted = false
    for (const payload of payloads) {
      const { data, error } = await supabase
        .from('productions').insert(payload).select('id').single()
      if (!error) {
        productionId = data.id
        console.log(`  ✅ Production creata: ${productionId} (payload: ${Object.keys(payload).join(', ')})`)
        if (!('slug' in payload)) {
          console.warn('  ⚠️  Esegui scripts/create-schema.sql in Supabase SQL Editor per lo schema completo')
        }
        inserted = true
        break
      }
      if (!isSchemaErr(error)) {
        // Errore genuino (non di schema) — non provare oltre
        console.error('  ❌ Production:', error.message)
        throw error
      }
      console.log(`  ℹ️  Payload ${JSON.stringify(payload)} non valido (${error.message.split('.')[0]}) — provo prossimo`)
    }
    if (!inserted) {
      throw new Error(
        'Impossibile creare production con nessun payload.\n' +
        '→ Esegui scripts/create-schema.sql in Supabase SQL Editor, poi rilancia lo script.'
      )
    }
  }

  // ── 5.2 LOCATIONS (Hotels + Hubs) ─────────────────────────────────────────
  console.log('\n[2/7] Locations (Hotels + Hubs)...')
  const hotelsRows   = readSheet(wb, 'Hotels')
  const hubsRows     = readSheet(wb, 'Hubs')

  const locations = []

  for (const r of hotelsRows) {
    const id = str(r['Pickup_ID'])
    if (!id) continue
    locations.push({
      id,
      production_id:        productionId,
      name:                 str(r['Hotel_Name']),
      is_hub:               false,
      lat:                  r['Lat']  != null ? parseFloat(String(r['Lat']).replace(',', '.'))  : null,
      lng:                  r['Lng']  != null ? parseFloat(String(r['Lng']).replace(',', '.'))  : null,
      default_pickup_point: str(r['Default_Pickup_Point']),
    })
  }

  for (const r of hubsRows) {
    const id = str(r['Pickup_ID'])
    if (!id) continue
    locations.push({
      id,
      production_id:        productionId,
      name:                 str(r['Hubs_Name']),
      is_hub:               true,
      lat:                  r['Lat']  != null ? parseFloat(String(r['Lat']).replace(',', '.'))  : null,
      lng:                  r['Lng']  != null ? parseFloat(String(r['Lng']).replace(',', '.'))  : null,
      default_pickup_point: str(r['Default_Pickup_Point']),
    })
  }

  await upsert(supabase, 'locations', locations, 'id', 'Locations')

  // ── 5.3 VEHICLES (Fleet) ──────────────────────────────────────────────────
  console.log('\n[3/7] Vehicles (Fleet)...')
  const fleetRows = readSheet(wb, 'Fleet')
  const vehicles  = []

  for (const r of fleetRows) {
    const id = str(r['Vehicle_ID'])
    if (!id) continue
    vehicles.push({
      id,
      production_id: productionId,
      vehicle_type:  str(r['Type']),
      capacity:      int(r['Capacity']),
      driver_name:   str(r['Driver_Name']),
      sign_code:     str(r['Sign_Code']),
      unit_default:  str(r['Unit_Default']),
      active:        true,
    })
  }

  await upsert(supabase, 'vehicles', vehicles, 'id', 'Vehicles')

  // ── 5.4 CREW (Crew_Master) ────────────────────────────────────────────────
  console.log('\n[4/7] Crew (Crew_Master)...')
  const crewRows = readSheet(wb, 'Crew_Master')
  const crew     = []
  // Mappa nome → crew_id (per trip_passengers)
  const nameToCrewId = {}

  for (const r of crewRows) {
    const id = str(r['Crew_ID'])
    // Salta righe formula (senza Crew_ID o con Full_Name che inizia con "[Formula")
    if (!id || id.startsWith('[')) continue
    const fullName = str(r['Full_Name'])
    if (!fullName || fullName.startsWith('[')) continue

    // Normalizza hotel_status
    const rawStatus = str(r['Hotel_Status'])
    const hotelStatus = ['CONFIRMED', 'PENDING', 'CHECKED_OUT'].includes(rawStatus)
      ? rawStatus : 'PENDING'

    // Normalizza travel_status
    const rawTravel = str(r['Travel_Status'])
    const travelStatus = ['IN', 'OUT', 'PRESENT'].includes(rawTravel) ? rawTravel : 'PRESENT'

    crew.push({
      id,
      production_id:  productionId,
      full_name:      fullName,
      department:     str(r['Dept']),
      hotel_id:       str(r['Hotel_ID']),
      hotel_status:   hotelStatus,
      travel_status:  travelStatus,
      arrival_date:   toISODate(r['Arrival_Date']),
      departure_date: toISODate(r['Departure_Date']),
      notes:          str(r['Notes']),
    })

    // Mappa nome (lowercase) → id per lookup trip_passengers
    nameToCrewId[fullName.toLowerCase()] = id
  }

  await upsert(supabase, 'crew', crew, 'id', 'Crew')

  // ── 5.5 SERVICE TYPES (Lists) ─────────────────────────────────────────────
  console.log('\n[5/7] Service Types (Lists)...')
  const listsRows    = readSheet(wb, 'Lists')
  const serviceTypes = []
  const serviceTypeMap = {}  // name → id (generato lato client per ora)
  let stOrder = 0

  // Genera UUID deterministico-like (uuid v4 fake per upsert) — usiamo insert+select
  // Raccogliamo solo i nomi unici non nulli dalla colonna Service_Type
  const stNames = new Set()
  for (const r of listsRows) {
    const name = str(r['Service_Type'])
    if (name && !name.startsWith('[')) stNames.add(name)
  }

  // Inserisci service_types e recupera gli id
  for (const name of stNames) {
    const { data: existing } = await supabase
      .from('service_types')
      .select('id')
      .eq('production_id', productionId)
      .eq('name', name)
      .maybeSingle()

    if (existing) {
      serviceTypeMap[name] = existing.id
    } else {
      const { data: inserted, error: stErr } = await supabase
        .from('service_types')
        .insert({ production_id: productionId, name, sort_order: stOrder++ })
        .select('id')
        .single()
      if (stErr) {
        console.error(`  ❌ ServiceType "${name}": ${stErr.message}`)
      } else {
        serviceTypeMap[name] = inserted.id
      }
    }
  }
  console.log(`  ✅ Service Types: ${stNames.size} tipi (${Object.keys(serviceTypeMap).join(', ')})`)

  // ── 5.6 ROUTES ────────────────────────────────────────────────────────────
  console.log('\n[6/7] Routes...')
  const routesRows  = readSheet(wb, 'Routes')
  const routes      = []
  // ID placeholder senza dati reali (H007-H010)
  const PLACEHOLDER = /^H0(0[7-9]|10)$/

  // Location IDs validi (per validare FK)
  const validLocationIds = new Set(locations.map(l => l.id))

  for (const r of routesRows) {
    const fromId = str(r['From_ID'])
    const toId   = str(r['To_ID'])
    // Salta righe senza ID, placeholder, o senza durata
    if (!fromId || !toId) continue
    if (PLACEHOLDER.test(fromId) || PLACEHOLDER.test(toId)) continue
    const duration = int(r['Duration'])
    if (duration === null || duration <= 0) continue
    // Salta se le location non esistono (potrebbero non essere nel foglio Hotels)
    if (!validLocationIds.has(fromId) || !validLocationIds.has(toId)) {
      console.warn(`  ⚠️  Rotta saltata — location sconosciuta: ${fromId} → ${toId}`)
      continue
    }

    const rawSource = str(r['Source'])
    const source = ['ORS', 'AUTO', 'MANUAL'].includes(rawSource) ? rawSource : 'AUTO'

    routes.push({
      production_id: productionId,
      from_id:       fromId,
      to_id:         toId,
      duration_min:  duration,
      source,
    })
  }

  await upsert(supabase, 'routes', routes, 'production_id,from_id,to_id', 'Routes')

  // ── 5.7 TRIPS + TRIP_PASSENGERS ───────────────────────────────────────────
  console.log('\n[7/7] Trips + Trip_Passengers...')
  const tripsRows = readSheet(wb, 'Trips')
  const trips     = []
  // trip_passengers: array di { trip_row_id (placeholder), trip_id, crew_names[] }
  // Risolveremo trip_row_id dopo l'insert dei trip
  const tripPaxPending = []

  for (const r of tripsRows) {
    const tripId = str(r['Trip_ID'])
    if (!tripId || tripId.startsWith('[')) continue

    const dateISO   = toISODate(r['Date'])
    if (!dateISO) continue  // riga senza data valida → salta

    // Pickup_ID e Dropoff_ID (colonne con gli ID veri, non i nomi display)
    const pickupId  = str(r['Pickup_ID'])
    const dropoffId = str(r['Dropoff_ID'])
    if (!pickupId || !dropoffId) continue

    // Tempi
    const callMin   = toMinutes(r['Call'])
    const pickupMin = toMinutes(r['Pickup_Time'])
    const startDt   = toTimestamp(r['Start_DT'], dateISO)
    const endDt     = toTimestamp(r['End_DT'],   dateISO)

    // Arr_Time → colonna TIME (es. "10:00:00")
    const arrTimeStr = toTimeString(r['Arr_Time'])

    // Service type lookup
    const stName    = str(r['Service_Type'])
    const stId      = stName ? (serviceTypeMap[stName] || null) : null

    // Status
    const rawStatus  = str(r['Status'])
    const validStatuses = ['PLANNED', 'BUSY', 'DONE', 'CANCELLED']
    const status = validStatuses.includes(rawStatus) ? rawStatus : 'PLANNED'

    // Pax count
    const paxCount  = int(r['Pax_Count(auto)']) ?? int(r['Pax_Count']) ?? 0

    // Vehicle (validazione FK opzionale)
    const vehicleId = str(r['Vehicle_ID'])

    trips.push({
      production_id:      productionId,
      trip_id:            tripId,
      date:               dateISO,
      vehicle_id:         vehicleId,
      driver_name:        str(r['Driver_Name(auto)']) || str(r['Driver_Name']),
      sign_code:          str(r['Sign_Code(auto)'])   || str(r['Sign_Code']),
      capacity:           int(r['Capacity(auto)'])    ?? int(r['Capacity']),
