        tripRowMap[key] = t.id
      }
    }
  }

  // Costruisce trip_passengers
  const tripPax = []
  let unmatchedCrew = 0

  for (const { tripId, dateISO, pickupId, dropoffId, names } of tripPaxPending) {
    const key       = `${tripId}|${pickupId}|${dropoffId}|${dateISO}`
    const tripRowId = tripRowMap[key]
    if (!tripRowId) {
